// ─── AUTH STORAGE (client-side demo only) ──────────────────────────────────
// IMPORTANT: This app has no backend. To let the demo simulate account
// creation and login, passwords are hashed with SHA-256 + a random per-user
// salt and stored in the browser's localStorage. This is NOT production
// security — it only prevents storing raw passwords in this browser. A real
// deployment MUST move authentication to a server: hash passwords with
// bcrypt/argon2, use HTTPS, rate-limit login attempts, and store data in a
// HIPAA-compliant database. Do not treat this as secure for real patient data.
const AUTH_KEY = "vytal_accounts";
const SESSION_KEY = "vytal_session";

function loadAccounts(){
  try{ return JSON.parse(localStorage.getItem(AUTH_KEY)) || {}; }catch{ return {}; }
}
function saveAccounts(accounts){
  try{ localStorage.setItem(AUTH_KEY, JSON.stringify(accounts)); }catch{}
}
function bufToHex(buf){
  return Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,"0")).join("");
}
async function hashPassword(password, salt){
  const enc = new TextEncoder();
  const digest = await crypto.subtle.digest("SHA-256", enc.encode(salt+":"+password));
  return bufToHex(digest);
}
function randomSalt(){
  const arr = new Uint8Array(16);
  crypto.getRandomValues(arr);
  return bufToHex(arr.buffer);
}
function normalizeIdentifier(method, value){
  return method==="phone" ? value.replace(/\D/g,"") : value.trim().toLowerCase();
}
function daysSince(dateStr){
  if(!dateStr) return 0;
  const ms = Date.now()-new Date(dateStr).getTime();
  return Math.max(0, Math.floor(ms/86400000));
}

