function MiniChart({data, color, height=52}){
  if(!data||data.length<2) return <div style={{height:`${height}px`,display:"flex",alignItems:"center",justifyContent:"center",color:T.textMuted,fontSize:"13px"}}>No data yet</div>;
  const min=Math.min(...data)-5, max=Math.max(...data)+5, range=max-min;
  const w=220,h=height;
  const pts=data.map((v,i)=>{const x=(i/(data.length-1))*w;const y=h-((v-min)/range)*h;return `${x},${y}`;});
  const area=`0,${h} ${pts.join(" ")} ${w},${h}`;
  return(
    <svg viewBox={`0 0 ${w} ${h}`} style={{width:"100%",height:`${height}px`}}>
      <defs><linearGradient id={`g${color.replace(/[^a-z0-9]/gi,"")}`} x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={color} stopOpacity="0.15"/><stop offset="100%" stopColor={color} stopOpacity="0.02"/></linearGradient></defs>
      <polygon points={area} fill={`url(#g${color.replace(/[^a-z0-9]/gi,"")})`}/>
      <polyline points={pts.join(" ")} fill="none" stroke={color} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/>
      <circle cx={pts[pts.length-1].split(",")[0]} cy={pts[pts.length-1].split(",")[1]} r="4" fill={color} stroke="white" strokeWidth="2"/>
    </svg>
  );
}

