function generateCode(){
  return String(Math.floor(100000 + Math.random()*900000));
}

function VerifyCode({pending, onVerified, onCancel}){
  const [code,setCode]=useState("");
  const [error,setError]=useState("");
  const [busy,setBusy]=useState(false);
  const [current,setCurrent]=useState(pending);
  const [cooldown,setCooldown]=useState(30);

  useEffect(()=>{
    if(cooldown<=0) return;
    const t=setInterval(()=>setCooldown(c=>Math.max(0,c-1)), 1000);
    return ()=>clearInterval(t);
  },[cooldown]);

  function resend(){
    setCurrent(c=>({...c, code:generateCode(), expiresAt:Date.now()+10*60*1000}));
    setCode("");
    setError("");
    setCooldown(30);
  }

  async function handleVerify(e){
    e.preventDefault();
    setError("");
    if(code.trim().length!==6){ setError("Enter the 6-digit code."); return; }
    setBusy(true);
    if(Date.now()>current.expiresAt){ setError("That code expired. Send a new one."); setBusy(false); return; }
    if(code.trim()!==current.code){ setError("Incorrect code. Please try again."); setBusy(false); return; }

    const accounts=loadAccounts();
    let account;
    if(current.mode==="signup"){
      account={method:current.method, identifier:current.identifier, salt:current.salt, hash:current.hash, createdAt:new Date().toISOString(), profile:null, verified:true};
    } else {
      account={...current.existingAccount, verified:true};
    }
    accounts[current.key]=account;
    saveAccounts(accounts);
    try{ localStorage.setItem(SESSION_KEY, current.key); }catch{}
    setBusy(false);
    onVerified({key:current.key, account});
  }

  const dest = current.method==="email" ? current.identifier : current.identifier;
  const destLabel = current.method==="email" ? "email" : "phone";

  return(
    <div style={{minHeight:"100vh",background:T.bg,display:"flex",alignItems:"center",justifyContent:"center",padding:"24px"}}>
      <div style={{width:"100%",maxWidth:"440px"}}>
        <div style={{textAlign:"center",marginBottom:"32px"}}>
          <div style={{display:"inline-flex",alignItems:"center",gap:"10px",background:T.navy,borderRadius:"16px",padding:"10px 20px"}}>
            <span style={{fontSize:"20px"}}>⚕️</span>
            <span style={{fontSize:"20px",fontWeight:"800",color:"white",letterSpacing:"-0.3px"}}>Vytal</span>
          </div>
        </div>

        <Card style={{padding:"36px"}}>
          <div style={{textAlign:"center",marginBottom:"22px"}}>
            <div style={{fontSize:"44px",marginBottom:"10px"}}>{current.method==="email"?"📧":"📱"}</div>
            <h2 style={{fontSize:"22px",fontWeight:"800",color:T.text,margin:"0 0 6px"}}>Verify your {destLabel}</h2>
            <p style={{fontSize:"14px",color:T.textSoft,margin:0}}>Enter the 6-digit code we sent to<br/><strong style={{color:T.text}}>{dest}</strong></p>
          </div>

          <div style={{background:T.amberLight,border:`1.5px solid ${T.amber}30`,borderRadius:"10px",padding:"12px 14px",marginBottom:"20px",fontSize:"12px",color:T.amber,lineHeight:"1.6"}}>
            🧪 <strong>Demo mode:</strong> this app has no email/SMS backend connected, so no real message was sent. Your code is <strong style={{fontFamily:T.mono,letterSpacing:"1px"}}>{current.code}</strong>. In production this would arrive by real {destLabel}.
          </div>

          <form onSubmit={handleVerify}>
            <div style={{marginBottom:"18px"}}>
              <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,display:"block",marginBottom:"6px",textTransform:"uppercase",letterSpacing:"0.5px"}}>Verification Code</label>
              <input value={code} onChange={e=>setCode(e.target.value.replace(/\D/g,"").slice(0,6))}
                inputMode="numeric" placeholder="000000" autoFocus maxLength={6}
                style={{width:"100%",fontSize:"26px",fontFamily:T.mono,fontWeight:"800",letterSpacing:"10px",textAlign:"center",padding:"16px",borderRadius:"12px",border:`2px solid ${T.border}`,outline:"none",color:T.text,background:T.bg}}/>
            </div>

            {error&&(
              <div style={{background:T.redLight,border:`1.5px solid ${T.red}30`,borderRadius:"10px",padding:"11px 14px",marginBottom:"16px",fontSize:"13px",color:T.red,fontWeight:"600"}}>
                ⚠️ {error}
              </div>
            )}

            <BigButton fullWidth disabled={busy}>{busy?"Verifying…":"Verify →"}</BigButton>
          </form>

          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:"18px"}}>
            <button type="button" onClick={onCancel} style={{background:"none",border:"none",cursor:"pointer",color:T.textSoft,fontSize:"13px",fontFamily:T.font,padding:0}}>← Back</button>
            <button type="button" onClick={resend} disabled={cooldown>0} style={{background:"none",border:"none",cursor:cooldown>0?"default":"pointer",color:cooldown>0?T.textMuted:T.navy,fontSize:"13px",fontFamily:T.font,fontWeight:"700",padding:0}}>
              {cooldown>0?`Resend code (${cooldown}s)`:"Resend code"}
            </button>
          </div>
        </Card>
      </div>
    </div>
  );
}

function Auth({onAuthenticated}){
  const [mode,setMode]=useState("signup"); // signup | login
  const [method,setMethod]=useState("email"); // email | phone
  const [identifier,setIdentifier]=useState("");
  const [password,setPassword]=useState("");
  const [confirm,setConfirm]=useState("");
  const [showPw,setShowPw]=useState(false);
  const [error,setError]=useState("");
  const [busy,setBusy]=useState(false);
  const [pending,setPending]=useState(null); // set once a code has been "sent"

  const idValid = method==="email"
    ? identifier.includes("@") && identifier.includes(".")
    : identifier.replace(/\D/g,"").length>=10;
  const pwValid = password.length>=8 && /[a-zA-Z]/.test(password) && /\d/.test(password);
  const matchValid = mode==="login" || (confirm.length>0 && password===confirm);

  function switchMode(m){ setMode(m); setError(""); setPassword(""); setConfirm(""); }
  function switchMethod(m){ setMethod(m); setIdentifier(""); setError(""); }

  async function handleSubmit(e){
    e.preventDefault();
    setError("");

    if(!idValid){ setError(method==="email" ? "Enter a valid email address." : "Enter a valid 10-digit phone number."); return; }

    if(mode==="signup"){
      if(!pwValid){ setError("Password must be at least 8 characters and include a letter and a number."); return; }
      if(password!==confirm){ setError("Passwords do not match."); return; }
    } else if(!password){
      setError("Enter your password."); return;
    }

    setBusy(true);
    try{
      const key=normalizeIdentifier(method, identifier);
      const accounts=loadAccounts();

      if(mode==="signup"){
        if(accounts[key]){
          setError(`An account already exists with that ${method==="email"?"email":"phone number"}. Try logging in instead.`);
          setBusy(false); return;
        }
        const salt=randomSalt();
        const hash=await hashPassword(password, salt);
        setPending({mode:"signup", key, method, identifier:identifier.trim(), salt, hash, code:generateCode(), expiresAt:Date.now()+10*60*1000});
      } else {
        const acct=accounts[key];
        if(!acct){ setError(`No account found with that ${method==="email"?"email":"phone number"}.`); setBusy(false); return; }
        const hash=await hashPassword(password, acct.salt);
        if(hash!==acct.hash){ setError("Incorrect password."); setBusy(false); return; }
        if(!acct.verified){
          setPending({mode:"login", key, method:acct.method, identifier:acct.identifier, existingAccount:acct, code:generateCode(), expiresAt:Date.now()+10*60*1000});
        } else {
          try{ localStorage.setItem(SESSION_KEY, key); }catch{}
          onAuthenticated({key, account:acct});
        }
      }
    }catch(err){
      setError("Something went wrong. Please try again.");
    }
    setBusy(false);
  }

  if(pending){
    return <VerifyCode pending={pending} onVerified={onAuthenticated} onCancel={()=>setPending(null)}/>;
  }

  return(
    <div style={{minHeight:"100vh",background:T.bg,display:"flex",alignItems:"center",justifyContent:"center",padding:"24px"}}>
      <div style={{width:"100%",maxWidth:"440px"}}>
        <div style={{textAlign:"center",marginBottom:"32px"}}>
          <div style={{display:"inline-flex",alignItems:"center",gap:"10px",background:T.navy,borderRadius:"16px",padding:"10px 20px"}}>
            <span style={{fontSize:"20px"}}>⚕️</span>
            <span style={{fontSize:"20px",fontWeight:"800",color:"white",letterSpacing:"-0.3px"}}>Vytal</span>
          </div>
        </div>

        <Card style={{padding:"36px"}}>
