};

function getRecommendedSpecialties(conditionIds=[]){
  const set=new Set(["Primary Care / Family Medicine"]);
  conditionIds.forEach(id=>{ const s=CONDITION_SPECIALTY[id]; if(s) set.add(s); });
  return Array.from(set);
}

function mapsSearchUrl(specialty, patient={}){
  const parts=[specialty.replace(/\s*\([^)]*\)/,"").trim()+" doctor near me"];
  const loc=[patient.city, patient.state, patient.zip, patient.country&&patient.country!=="United States"?patient.country:""].filter(Boolean).join(", ");
  const q=loc?`${parts[0]} in ${loc}`:parts[0];
  return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(q)}`;
}

