      </BigButton>
      {data.conditions.length===0&&<p style={{textAlign:"center",fontSize:"13px",color:T.textMuted,marginTop:"10px"}}>Select at least one condition to continue</p>}
    </div>,
  ];

  return(
    <div style={{minHeight:"100vh",background:T.bg,display:"flex",alignItems:"center",justifyContent:"center",padding:"24px"}}>
      <div style={{width:"100%",maxWidth:"520px"}}>
