            <span style={{fontSize:"20px",fontWeight:"800",color:"white",letterSpacing:"-0.3px"}}>Vytal</span>
          </div>
        </div>

        {/* Progress dots */}
        {step>0&&(
          <div style={{display:"flex",justifyContent:"center",gap:"8px",marginBottom:"24px"}}>
            {[
