        )}

        <Card style={{padding:"40px"}}>
          {steps[step]}
        </Card>

        {step>0&&(
          <button onClick={()=>setStep(s=>s-1)} style={{display:"block",margin:"16px auto 0",background:"transparent",border:"none",cursor:"pointer",color:T.textSoft,fontSize:"14px",fontFamily:T.font}}>
            ← Go back
          </button>
        )}
      </div>
    </div>
  );
}

// ─── LIVE READING HOOK ────────────────────────────────────────────────────────
function useLive(base, variance, interval=3000){
  const [val,setVal]=useState(base);
  useEffect(()=>{
    const t=setInterval(()=>setVal(v=>Math.max(base*0.88,Math.min(base*1.12,Math.round(v+(Math.random()-0.48)*variance*2)))),interval);
    return ()=>clearInterval(t);
  },[base,variance,interval]);
  return val;
}

// ─── AI COACH ─────────────────────────────────────────────────────────────────
function AICoach({patient}){
  const [messages,setMessages]=useState([{role:"assistant",content:`Hi ${patient.name} 😊 I'm your Vytal health coach. I'm here to help you understand your health, answer questions about your medications, and support you day to day. What would you like to know?`}]);
  const [input,setInput]=useState("");
  const [loading,setLoading]=useState(false);
  const bottomRef=useRef(null);
  useEffect(()=>{bottomRef.current?.scrollIntoView({behavior:"smooth"});},[messages]);

  async function send(){
    if(!input.trim()||loading) return;
    const msg=input.trim(); setInput(""); setLoading(true);
    setMessages(m=>[...m,{role:"user",content:msg}]);
    try{
      const history=[...messages,{role:"user",content:msg}].map(m=>({role:m.role,content:m.content}));
      const res=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({model:"claude-sonnet-4-6",max_tokens:1000,
          system:`You are Vytal — a warm, friendly AI health coach for people managing chronic conditions. Speak in plain, simple English. No medical jargon. Use short sentences. Be encouraging and positive. Patient: ${patient.name}, age ${patient.age}. Conditions: ${patient.conditions.join(", ")}. Vitals: glucose avg 148 (target under 130), BP 142/89, weight 181 lbs trending down, heart rate 77. Medications: Metformin, Lisinopril, Atorvastatin (missed 2 nights), Aspirin, Metoprolol. Always remind that for serious concerns they should contact their doctor. Keep responses to 2-4 short sentences unless they need more detail.`,
          messages:history})});
      const data=await res.json();
      const reply=data.content?.find(b=>b.type==="text")?.text||"I had trouble responding. Please try again.";
      setMessages(m=>[...m,{role:"assistant",content:reply}]);
    }catch{setMessages(m=>[...m,{role:"assistant",content:"Connection issue. Please try again."}]);}
    finally{setLoading(false);}
  }

  const quick=["Why is my blood sugar high?","Did I take all my meds?","What should I eat today?","How is my BP doing?"];

  return(
    <div style={{display:"flex",flexDirection:"column",height:"100%",minHeight:"520px"}}>
      <div style={{flex:1,overflowY:"auto",padding:"24px",display:"flex",flexDirection:"column",gap:"16px"}}>
        {messages.map((m,i)=>(
          <div key={i} style={{display:"flex",justifyContent:m.role==="user"?"flex-end":"flex-start",gap:"12px",alignItems:"flex-end"}}>
            {m.role==="assistant"&&(
              <div style={{width:"36px",height:"36px",borderRadius:"50%",background:T.navy,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"16px",flexShrink:0}}>⚕️</div>
            )}
            <div style={{maxWidth:"78%",padding:"14px 18px",
              borderRadius:m.role==="user"?"20px 20px 6px 20px":"6px 20px 20px 20px",
              background:m.role==="user"?T.navy:T.bgSoft,
              fontSize:"15px",lineHeight:"1.65",color:m.role==="user"?"white":T.text,
              boxShadow:"0 2px 8px rgba(0,0,0,0.06)",
            }}>{m.content}</div>
          </div>
        ))}
        {loading&&(
          <div style={{display:"flex",gap:"12px",alignItems:"flex-end"}}>
            <div style={{width:"36px",height:"36px",borderRadius:"50%",background:T.navy,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"16px"}}>⚕️</div>
            <div style={{background:T.bgSoft,borderRadius:"6px 20px 20px 20px",padding:"14px 18px",display:"flex",gap:"6px",alignItems:"center"}}>
              {[0,1,2].map(i=><div key={i} style={{width:"8px",height:"8px",borderRadius:"50%",background:T.navy,animation:`bounce 1s ease-in-out ${i*0.15}s infinite`}}/>)}
            </div>
          </div>
        )}
        <div ref={bottomRef}/>
      </div>
      <div style={{padding:"0 24px 14px",display:"flex",gap:"8px",flexWrap:"wrap"}}>
        {quick.map((q,i)=>(
          <button key={i} onClick={()=>setInput(q)} style={{background:T.bgSoft,border:`1.5px solid ${T.border}`,borderRadius:"20px",padding:"8px 14px",cursor:"pointer",color:T.textMid,fontSize:"13px",fontFamily:T.font,fontWeight:"500"}}>
            {q}
          </button>
        ))}
      </div>
      <div style={{padding:"14px 24px 24px",display:"flex",gap:"10px",borderTop:`1.5px solid ${T.border}`}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&send()}
          placeholder="Type your question here…"
          style={{flex:1,background:T.bgSoft,border:`2px solid ${input?T.navy:T.border}`,borderRadius:"14px",padding:"13px 18px",color:T.text,fontSize:"15px",fontFamily:T.font,outline:"none"}}/>
        <button onClick={send} disabled={loading||!input.trim()} style={{background:T.navy,border:"none",borderRadius:"14px",padding:"13px 22px",cursor:"pointer",color:"white",fontSize:"15px",fontFamily:T.font,fontWeight:"700",opacity:(!input.trim()||loading)?0.4:1}}>Send</button>
      </div>
    </div>
  );
}

