              <div style={{background:T.redLight,borderRadius:"14px",padding:"16px",border:`1.5px solid ${T.red}20`}}>
                <div style={{fontSize:"13px",fontWeight:"700",color:T.red,marginBottom:"6px"}}>📞 When To Call Your Doctor</div>
                <p style={{margin:0,fontSize:"13px",color:T.textMid,lineHeight:"1.5"}}>{analysis.when_to_call_doctor}</p>
              </div>
