          </div>

          <div style={{background:T.bgSoft,borderRadius:"12px",padding:"14px 18px",border:`1.5px solid ${T.border}`,fontSize:"13px",color:T.textSoft}}>
            ⚠️ This is an AI health summary to help you stay informed — it is not a medical diagnosis. Always speak with your doctor about your health concerns.
          </div>
        </div>
      )}
    </div>
  );
