              </div>
              <div style={{fontSize:"12px",fontWeight:"700",color:T.red,textTransform:"uppercase",letterSpacing:"1px",marginBottom:"8px"}}>Eat Less Of</div>
              <div style={{display:"flex",flexWrap:"wrap",gap:"6px"}}>
                {plan.nutrition.eat_less.map((f,i)=><Pill key={i} color={T.red} bg={T.redLight}>⚠️ {f}</Pill>)}
              </div>
            </div>

            {/* Exercise */}
            <div style={{background:T.bgSoft,borderRadius:"14px",padding:"18px",border:`1.5px solid ${T.border}`}}>
              <div style={{fontSize:"16px",fontWeight:"700",color:T.text,marginBottom:"10px"}}>🚶 Movement This Week</div>
              <p style={{margin:"0 0 14px",fontSize:"14px",color:T.textMid,lineHeight:"1.6"}}>{plan.exercise.tip}</p>
              {plan.exercise.days.map((d,i)=>(
                <div key={i} style={{display:"flex",gap:"10px",alignItems:"center",padding:"8px 0",borderBottom:i<6?`1px solid ${T.border}`:""}}>
                  <div style={{width:"36px",fontSize:"12px",fontWeight:"700",color:T.textMuted,flexShrink:0}}>{d.day}</div>
                  <div style={{flex:1,fontSize:"13px",color:T.textMid}}>{d.activity}</div>
                  <Pill color={fc[d.feel]||T.navy} bg={fl[d.feel]||T.navyXLight}>{d.feel}</Pill>
                </div>
              ))}
            </div>
          </div>

          {/* Daily habits */}
          <div style={{background:T.navyXLight,borderRadius:"14px",padding:"18px 22px",border:`1.5px solid ${T.navyLight}`}}>
            <div style={{fontSize:"16px",fontWeight:"700",color:T.navy,marginBottom:"12px"}}>⭐ Do These Every Day</div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:"10px"}}>
              {plan.daily_habits.map((h,i)=>(
                <div key={i} style={{background:"white",borderRadius:"12px",padding:"14px",textAlign:"center",boxShadow:"0 2px 6px rgba(0,0,0,0.04)"}}>
                  <div style={{fontSize:"22px",marginBottom:"6px"}}>{"🌟💧🧘".split("")[i]||"✅"}</div>
                  <div style={{fontSize:"13px",color:T.textMid,fontWeight:"500",lineHeight:"1.4"}}>{h}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── CONNECTED DEVICES ────────────────────────────────────────────────────────
function ConnectedDevices(){
  const [active,setActive]=useState(null);
  const [view,setView]=useState("list"); // list | connect | setup | connected
  const [setupStep,setSetupStep]=useState(0);
  const [connecting,setConnecting]=useState(false);
  const [connectedDevices,setConnectedDevices]=useState([]);
  const [selectedDevice,setSelectedDevice]=useState(null);
  const liveG=useLive(148,4,2500);
  const liveBP=useLive(140,3,4000);
  const liveHR=useLive(77,2,1800);
  const liveO=useLive(97,1,3500);

  const getLive=(id)=>{
    if(id==="glucometer") return {val:`${liveG}`,unit:"mg/dL"};
    if(id==="bp_cuff") return {val:`${liveBP}/89`,unit:"mmHg"};
    if(id==="watch") return {val:`${liveHR}`,unit:"bpm"};
    if(id==="pulse_ox") return {val:`${liveO}`,unit:"% SpO2"};
    if(id==="scale") return {val:"181",unit:"lbs"};
    return {val:"—",unit:""};
  };

  // All available devices to add
  const AVAILABLE_DEVICES = [
    {id:"glucometer", name:"Blood Glucose Monitor", brand:"Compatible: Dexcom, Abbott, Contour, OneTouch", icon:"🩸", color:T.amber, light:T.amberLight, type:"bluetooth",
      what:"Measures your blood sugar level",
      steps:["Turn on your glucometer","Press and hold the Bluetooth button for 3 seconds until it flashes","Open Bluetooth on your phone and look for your device name","Tap your device name below to pair","Keep the meter within 3 feet until connected"],
      compatible:["Dexcom G6/G7","Abbott FreeStyle Libre 2/3","Contour NEXT ONE","OneTouch Verio Reflect","Accu-Chek Guide"],
      manualFields:[{label:"Blood Sugar Reading",placeholder:"e.g. 148",unit:"mg/dL"},{label:"Test Time",placeholder:"e.g. 8:00 AM",unit:""}]},
    {id:"bp_cuff", name:"Blood Pressure Monitor", brand:"Compatible: Omron, Withings, iHealth, Beurer", icon:"❤️", color:T.red, light:T.redLight, type:"bluetooth",
      what:"Measures your blood pressure and pulse",
      steps:["Turn on your blood pressure monitor","Press and hold the Bluetooth button (usually marked BT or 📶) for 3 seconds","Look for the device name in the list below","Tap to connect — keep your arm still","First reading will sync automatically"],
      compatible:["Omron Evolv","Omron Platinum","Withings BPM Connect","iHealth Track","Beurer BM57"],
      manualFields:[{label:"Systolic (top number)",placeholder:"e.g. 140",unit:"mmHg"},{label:"Diastolic (bottom number)",placeholder:"e.g. 89",unit:"mmHg"}]},
    {id:"scale", name:"Smart Scale", brand:"Compatible: Withings, Fitbit, Garmin, Eufy", icon:"⚖️", color:T.blue, light:T.blueLight, type:"wifi",
      what:"Measures your weight and body composition",
      steps:["Download the scale manufacturer's app first (e.g. Withings Health Mate)","Connect the scale to your home WiFi using the manufacturer's app","Once connected to WiFi, open Vytal and tap Sync","Step on the scale — your weight syncs automatically","Data appears in your Vytal dashboard within 30 seconds"],
      compatible:["Withings Body+","Withings Body Scan","Fitbit Aria Air","Garmin Index S2","Eufy Smart Scale P2"],
      manualFields:[{label:"Your Weight",placeholder:"e.g. 181",unit:"lbs"}]},
    {id:"watch", name:"Smartwatch / Fitness Tracker", brand:"Compatible: Apple Watch, Fitbit, Garmin, Samsung", icon:"⌚", color:T.purple, light:T.purpleLight, type:"app",
      what:"Tracks heart rate, steps, sleep, and activity",
      steps:["Make sure your smartwatch is paired to your phone","On iPhone: open Health app → Browse → allow Vytal access","On Android: open Google Fit → Settings → allow Vytal access","Your heart rate, steps and sleep will sync automatically","Data appears in Vytal within a few minutes"],
      compatible:["Apple Watch (all models)","Fitbit Sense/Versa/Charge","Garmin Venu/Fenix","Samsung Galaxy Watch","Google Pixel Watch"],
      manualFields:[{label:"Resting Heart Rate",placeholder:"e.g. 72",unit:"bpm"}]},
    {id:"pulse_ox", name:"Pulse Oximeter", brand:"Compatible: Masimo, Nonin, iHealth, Wellue", icon:"💨", color:T.teal, light:T.tealLight, type:"bluetooth",
      what:"Measures blood oxygen level (SpO2) and heart rate",
      steps:["Turn on your pulse oximeter","Press and hold the power button until Bluetooth icon appears","Find your device in the list below and tap to connect","Clip it to your finger — keep still for 30 seconds","Reading syncs to Vytal automatically"],
      compatible:["Masimo MightySat","Nonin 3230","iHealth Air","Wellue O2Ring","Beurer PO60"],
      manualFields:[{label:"Oxygen Level (SpO2)",placeholder:"e.g. 97",unit:"%"},{label:"Heart Rate",placeholder:"e.g. 75",unit:"bpm"}]},
    {id:"cgm", name:"Continuous Glucose Monitor (CGM)", brand:"Compatible: Dexcom G7, Abbott Libre 3, Medtronic", icon:"🔵", color:T.navyMid, light:T.navyXLight, type:"sensor",
      what:"Continuously monitors blood sugar every 5 minutes — no finger pricks",
      steps:["Apply the CGM sensor to the back of your upper arm (a doctor or nurse can help)","Download the manufacturer app (Dexcom, LibreLink, or Medtronic)","Scan the sensor with your phone to activate it","Allow the app to share data with Vytal in settings","CGM readings appear in Vytal automatically every 5 minutes"],
      compatible:["Dexcom G7","Abbott FreeStyle Libre 3","Medtronic Guardian 4","Eversense E3"],
      manualFields:[]},
    {id:"glucometer2", name:"Smart Insulin Pen", brand:"Compatible: NovoPen, InPen, Bigfoot Unity", icon:"💉", color:"#059669", light:"#D1FAE5", type:"bluetooth",
      what:"Tracks insulin doses automatically",
      steps:["Insert the smart pen cap onto your insulin pen","Turn on Bluetooth on your phone","Open the pen manufacturer's app to pair","Once paired, each dose is recorded automatically","Doses sync to Vytal so your coach can track your insulin"],
      compatible:["NovoPen 6","InPen Smart Insulin Pen","Bigfoot Unity","Pendiq 2.0"],
      manualFields:[{label:"Insulin Dose",placeholder:"e.g. 10",unit:"units"}]},
    {id:"thermometer", name:"Smart Thermometer", brand:"Compatible: Kinsa, iHealth, Braun", icon:"🌡️", color:"#DC2626", light:"#FEE2E2", type:"bluetooth",
      what:"Tracks your temperature — useful for detecting infections early",
      steps:["Turn on your smart thermometer","Enable Bluetooth on your phone","Open manufacturer app to pair (one-time setup)","Take a temperature reading — it syncs instantly","Vytal will alert you if your temperature is elevated"],
      compatible:["Kinsa QuickCare","iHealth No-Touch","Braun ThermoScan 9","Withings Thermo"],
      manualFields:[{label:"Temperature",placeholder:"e.g. 98.6",unit:"°F"}]},
  ];

  function startConnect(device){
    setSelectedDevice(device);
    setSetupStep(0);
    setView("setup");
    setConnecting(false);
  }

  function simulateConnect(){
    setConnecting(true);
    setTimeout(()=>{
      setConnectedDevices(prev=>[...prev.filter(d=>d.id!==selectedDevice.id),{...DEVICES.find(d=>d.id===selectedDevice.id)||selectedDevice,status:"connected",lastSync:"Just now",battery:100}]);
      setConnecting(false);
      setView("success");
    },3000);
  }

  const notConnected=AVAILABLE_DEVICES.filter(d=>!connectedDevices.find(c=>c.id===d.id));

  // ── LIST VIEW ──────────────────────────────────────────────────────────────
  if(view==="list") return(
    <div>
      {/* Empty state — no devices yet */}
      {connectedDevices.length===0&&(
        <div style={{background:`linear-gradient(135deg,${T.navyXLight},${T.bgSoft})`,border:`2px dashed ${T.navyLight}`,borderRadius:"16px",padding:"36px",textAlign:"center",marginBottom:"28px"}}>
          <div style={{fontSize:"48px",marginBottom:"16px"}}>📡</div>
          <h3 style={{margin:"0 0 8px",fontSize:"20px",fontWeight:"800",color:T.navy}}>No devices connected yet</h3>
          <p style={{margin:"0 0 20px",fontSize:"14px",color:T.textSoft,maxWidth:"360px",marginLeft:"auto",marginRight:"auto",lineHeight:"1.6"}}>Connect your health devices below to get live readings. No device? You can also enter readings manually.</p>
          <div style={{display:"flex",gap:"10px",justifyContent:"center",flexWrap:"wrap"}}>
            {["Blood Glucose Monitor","Blood Pressure Monitor","Smart Scale","Smartwatch"].map((d,i)=>(
              <Pill key={i} color={T.navy} bg={T.navyXLight}>{d}</Pill>
            ))}
          </div>
        </div>
      )}

      {/* Connected devices */}
      {connectedDevices.length>0&&(
        <div style={{marginBottom:"28px"}}>
          <div style={{fontSize:"14px",fontWeight:"800",color:T.text,marginBottom:"14px"}}>
            ✅ {connectedDevices.length} Device{connectedDevices.length>1?"s":""} Connected
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:"12px"}}>
            {connectedDevices.map(d=>{
              const live=getLive(d.id);
              const avail=AVAILABLE_DEVICES.find(a=>a.id===d.id);
              return(
                <Card key={d.id} accent={avail?.color||T.green} style={{padding:"18px"}}>
                  <div style={{display:"flex",gap:"12px",alignItems:"center",marginBottom:"12px"}}>
                    <div style={{fontSize:"28px"}}>{avail?.icon||"📱"}</div>
                    <div style={{flex:1}}>
                      <div style={{fontSize:"14px",fontWeight:"700",color:T.text}}>{avail?.name||d.name}</div>
                      <div style={{fontSize:"12px",color:T.textMuted}}>{d.brand}</div>
                    </div>
                    <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:"4px"}}>
                      <div style={{display:"flex",gap:"6px",alignItems:"center"}}>
                        <div style={{width:"8px",height:"8px",borderRadius:"50%",background:T.green,animation:"pulse 2s infinite"}}/>
                        <span style={{fontSize:"11px",color:T.green,fontWeight:"700"}}>LIVE</span>
                      </div>
                      <div style={{fontSize:"11px",color:T.textMuted}}>🔋 {d.battery}%</div>
                    </div>
                  </div>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-end"}}>
                    <div>
                      <div style={{fontSize:"28px",fontWeight:"800",color:avail?.color||T.green,fontFamily:T.mono}}>{live.val}</div>
                      <div style={{fontSize:"12px",color:T.textMuted}}>{live.unit} · {d.lastSync}</div>
                    </div>
                    <button onClick={()=>startConnect(avail||d)} style={{background:"transparent",border:`1.5px solid ${T.border}`,borderRadius:"8px",padding:"6px 12px",cursor:"pointer",color:T.textSoft,fontSize:"12px",fontFamily:T.font}}>Settings</button>
                  </div>
                </Card>
              );
            })}
          </div>
        </div>
      )}

      {/* Add new device */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"14px"}}>
        <div style={{fontSize:"14px",fontWeight:"800",color:T.text}}>➕ Add a Device</div>
        <div style={{fontSize:"13px",color:T.textSoft}}>{notConnected.length} available to connect</div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(260px,1fr))",gap:"12px"}}>
        {notConnected.map(d=>(
          <button key={d.id} onClick={()=>startConnect(d)}
            style={{background:"white",border:`2px solid ${T.border}`,borderRadius:"16px",padding:"18px",cursor:"pointer",textAlign:"left",transition:"all 0.15s",display:"flex",gap:"14px",alignItems:"flex-start"}}>
            <div style={{fontSize:"32px",flexShrink:0}}>{d.icon}</div>
            <div style={{flex:1}}>
              <div style={{fontSize:"14px",fontWeight:"700",color:T.text,marginBottom:"4px"}}>{d.name}</div>
              <div style={{fontSize:"12px",color:T.textMuted,marginBottom:"8px"}}>{d.what}</div>
              <div style={{display:"flex",gap:"6px",alignItems:"center"}}>
                <Pill color={d.type==="bluetooth"?T.blue:d.type==="wifi"?T.green:d.type==="app"?T.purple:"#B45309"}
                  bg={d.type==="bluetooth"?T.blueLight:d.type==="wifi"?T.greenLight:d.type==="app"?T.purpleLight:"#FEF3C7"}>
                  {d.type==="bluetooth"?"📶 Bluetooth":d.type==="wifi"?"📡 Wi-Fi":d.type==="app"?"📱 Phone App":"🩹 Sensor"}
                </Pill>
              </div>
            </div>
            <div style={{color:T.textMuted,fontSize:"18px",flexShrink:0}}>→</div>
          </button>
        ))}
      </div>

      {/* Manual entry tip */}
      <div style={{marginTop:"24px",background:T.navyXLight,border:`1.5px solid ${T.navyLight}`,borderRadius:"14px",padding:"18px 20px",display:"flex",gap:"14px",alignItems:"center"}}>
        <div style={{fontSize:"28px"}}>✏️</div>
        <div>
          <div style={{fontSize:"14px",fontWeight:"700",color:T.navy,marginBottom:"4px"}}>Don't have a smart device?</div>
          <div style={{fontSize:"13px",color:T.textSoft}}>No problem — you can manually enter your readings (blood sugar, blood pressure, weight) directly in Vytal and your AI coach will still track them for you.</div>
        </div>
      </div>
    </div>
  );

  // ── SETUP VIEW ─────────────────────────────────────────────────────────────
  if(view==="setup"&&selectedDevice) return(
    <div style={{maxWidth:"640px"}}>
      <button onClick={()=>setView("list")} style={{background:"transparent",border:"none",cursor:"pointer",color:T.textSoft,fontSize:"14px",fontFamily:T.font,marginBottom:"20px",padding:0,display:"flex",alignItems:"center",gap:"6px"}}>
        ← Back to devices
      </button>

      <Card style={{overflow:"hidden"}}>
        {/* Header */}
        <div style={{background:selectedDevice.light,padding:"24px 28px",borderBottom:`1.5px solid ${T.border}`,display:"flex",gap:"16px",alignItems:"center"}}>
          <div style={{fontSize:"44px"}}>{selectedDevice.icon}</div>
          <div>
            <h3 style={{margin:"0 0 4px",fontSize:"20px",fontWeight:"800",color:T.text}}>{selectedDevice.name}</h3>
            <p style={{margin:"0 0 8px",fontSize:"13px",color:T.textSoft}}>{selectedDevice.brand}</p>
            <Pill color={selectedDevice.type==="bluetooth"?T.blue:selectedDevice.type==="wifi"?T.green:selectedDevice.type==="app"?T.purple:"#B45309"}
              bg="white">
              {selectedDevice.type==="bluetooth"?"📶 Bluetooth":selectedDevice.type==="wifi"?"📡 Wi-Fi":selectedDevice.type==="app"?"📱 Syncs via Phone App":"🩹 Wearable Sensor"}
            </Pill>
          </div>
        </div>

        <div style={{padding:"24px 28px"}}>
          {/* Compatible devices */}
          <div style={{marginBottom:"24px"}}>
            <div style={{fontSize:"13px",fontWeight:"700",color:T.textMuted,textTransform:"uppercase",letterSpacing:"1px",marginBottom:"10px"}}>Works With</div>
            <div style={{display:"flex",gap:"6px",flexWrap:"wrap"}}>
              {selectedDevice.compatible.map((c,i)=><Pill key={i} color={T.textSoft} bg={T.bgMuted}>{c}</Pill>)}
            </div>
          </div>

          {/* Step by step instructions */}
          <div style={{marginBottom:"24px"}}>
            <div style={{fontSize:"13px",fontWeight:"700",color:T.textMuted,textTransform:"uppercase",letterSpacing:"1px",marginBottom:"14px"}}>How To Connect — Follow These Steps</div>
            {selectedDevice.steps.map((step,i)=>(
              <div key={i} style={{display:"flex",gap:"14px",padding:"14px 0",borderBottom:i<selectedDevice.steps.length-1?`1px solid ${T.border}`:"",alignItems:"flex-start"}}>
                <div style={{width:"28px",height:"28px",borderRadius:"50%",background:i<setupStep?T.green:i===setupStep?selectedDevice.color:T.bgMuted,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"13px",fontWeight:"800",color:i<setupStep?"white":i===setupStep?"white":T.textMuted,flexShrink:0}}>
                  {i<setupStep?"✓":i+1}
                </div>
                <div style={{flex:1,paddingTop:"3px"}}>
                  <p style={{margin:0,fontSize:"14px",color:i<=setupStep?T.text:T.textMuted,lineHeight:"1.6",fontWeight:i===setupStep?"600":"400"}}>{step}</p>
                  {i===setupStep&&i<selectedDevice.steps.length-1&&(
                    <button onClick={()=>setSetupStep(s=>s+1)} style={{marginTop:"10px",background:selectedDevice.light,border:`1.5px solid ${selectedDevice.color}40`,borderRadius:"8px",padding:"7px 16px",cursor:"pointer",color:selectedDevice.color,fontSize:"13px",fontFamily:T.font,fontWeight:"700"}}>
                      Done, next step →
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>

          {/* Connect button — shows after all steps read */}
          {setupStep>=selectedDevice.steps.length-1&&(
            <div>
              {selectedDevice.type==="bluetooth"&&(
                <div style={{background:T.bgSoft,borderRadius:"14px",padding:"20px",marginBottom:"16px",border:`1.5px solid ${T.border}`}}>
                  <div style={{fontSize:"13px",fontWeight:"700",color:T.textMuted,textTransform:"uppercase",letterSpacing:"1px",marginBottom:"12px"}}>📶 Nearby Bluetooth Devices</div>
                  {connecting?(
                    <div style={{textAlign:"center",padding:"20px"}}>
                      <div style={{width:"36px",height:"36px",border:`3px solid ${T.border}`,borderTop:`3px solid ${selectedDevice.color}`,borderRadius:"50%",animation:"spin 0.8s linear infinite",margin:"0 auto 12px"}}/>
                      <div style={{fontSize:"14px",color:T.textSoft}}>Connecting to {selectedDevice.name}…</div>
                    </div>
                  ):(
                    <div style={{display:"flex",flexDirection:"column",gap:"8px"}}>
                      {["Your Device (tap to connect)","Unknown Device","Unknown Device"].map((name,i)=>(
                        <button key={i} onClick={i===0?simulateConnect:null} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"12px 16px",background:i===0?"white":T.bgSoft,border:`1.5px solid ${i===0?selectedDevice.color:T.border}`,borderRadius:"10px",cursor:i===0?"pointer":"default",fontFamily:T.font}}>
                          <div style={{display:"flex",gap:"10px",alignItems:"center"}}>
                            <div style={{width:"8px",height:"8px",borderRadius:"50%",background:i===0?selectedDevice.color:T.textMuted,animation:i===0?"pulse 1.5s infinite":"none"}}/>
                            <span style={{fontSize:"14px",color:i===0?T.text:T.textMuted}}>{i===0?selectedDevice.name.split(" ")[0]+"-A4B2":name}</span>
                          </div>
                          {i===0&&<span style={{fontSize:"13px",color:selectedDevice.color,fontWeight:"700"}}>Connect →</span>}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              )}

              {selectedDevice.type!=="bluetooth"&&(
                <BigButton onClick={simulateConnect} color={selectedDevice.color} fullWidth>
                  {connecting?"Connecting…":"✓ I've Completed All Steps — Connect Now"}
                </BigButton>
              )}

              {/* Manual entry option */}
              {selectedDevice.manualFields.length>0&&(
                <div style={{marginTop:"16px",background:T.bgSoft,borderRadius:"12px",padding:"16px 20px",border:`1.5px solid ${T.border}`}}>
                  <div style={{fontSize:"13px",fontWeight:"700",color:T.textMid,marginBottom:"12px"}}>✏️ Or enter a reading manually</div>
                  <div style={{display:"flex",flexDirection:"column",gap:"10px"}}>
                    {selectedDevice.manualFields.map((f,i)=>(
                      <div key={i} style={{display:"flex",gap:"10px",alignItems:"center"}}>
                        <input placeholder={f.placeholder} style={{flex:1,padding:"10px 14px",borderRadius:"10px",border:`1.5px solid ${T.border}`,fontSize:"15px",fontFamily:T.font,color:T.text,background:"white",outline:"none"}}/>
                        {f.unit&&<span style={{fontSize:"13px",color:T.textMuted,fontWeight:"600",flexShrink:0}}>{f.unit}</span>}
                      </div>
                    ))}
                    <button style={{background:T.navy,border:"none",borderRadius:"10px",padding:"11px",cursor:"pointer",color:"white",fontSize:"14px",fontFamily:T.font,fontWeight:"700"}}>Save Reading</button>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </Card>
    </div>
  );

  // ── SUCCESS VIEW ───────────────────────────────────────────────────────────
  if(view==="success"&&selectedDevice) return(
    <div style={{maxWidth:"520px",margin:"0 auto",textAlign:"center",padding:"40px 20px"}}>
      <div style={{fontSize:"72px",marginBottom:"20px"}}>🎉</div>
      <h2 style={{margin:"0 0 10px",fontSize:"26px",fontWeight:"800",color:T.text}}>Device Connected!</h2>
      <p style={{color:T.textSoft,fontSize:"16px",lineHeight:"1.7",margin:"0 0 28px"}}>
        Your <strong style={{color:T.text}}>{selectedDevice.name}</strong> is now connected to Vytal. Readings will sync automatically and appear on your dashboard.
      </p>
      <Card style={{padding:"20px",marginBottom:"24px",textAlign:"left"}}>
        {[
          {emoji:"📊",label:"Dashboard",desc:"Your readings now appear on the main dashboard"},
          {emoji:"🤖",label:"AI Coach",desc:"Your AI coach can now see your device data"},
          {emoji:"🔔",label:"Alerts",desc:"You'll get an alert if readings go out of range"},
          {emoji:"🔄",label:"Auto-sync",desc:"Data syncs automatically — no manual entry needed"},
        ].map((item,i)=>(
          <div key={i} style={{display:"flex",gap:"12px",padding:"10px 0",borderBottom:i<3?`1px solid ${T.border}`:"",alignItems:"center"}}>
            <span style={{fontSize:"20px"}}>{item.emoji}</span>
            <div><div style={{fontSize:"14px",fontWeight:"600",color:T.text}}>{item.label}</div><div style={{fontSize:"12px",color:T.textMuted}}>{item.desc}</div></div>
          </div>
        ))}
      </Card>
      <div style={{display:"flex",gap:"12px",justifyContent:"center"}}>
        <BigButton onClick={()=>{setView("list");setSelectedDevice(null);setSetupStep(0);}} color={selectedDevice.color}>
          ✓ Done — View My Devices
        </BigButton>
        <BigButton onClick={()=>{setSetupStep(0);setView("list");setTimeout(()=>startConnect(notConnected[0]),100);}} outline>
          ➕ Add Another Device
        </BigButton>
      </div>
    </div>
  );

  return null;
}


// ─── LAB ORDERS ───────────────────────────────────────────────────────────────
function LabOrders(){
  const [cart,setCart]=useState([]);
  const [view,setView]=useState("order");
  const [ordered,setOrdered]=useState(false);
  const [ordering,setOrdering]=useState(false);

  function toggle(lab){setCart(c=>c.find(x=>x.id===lab.id)?c.filter(x=>x.id!==lab.id):[...c,lab]);}
  const inCart=(id)=>!!cart.find(x=>x.id===id);
  const total=cart.reduce((a,b)=>a+b.price,0);

  function place(){setOrdering(true);setTimeout(()=>{setOrdering(false);setOrdered(true);setCart([]);},2500);}

  return(
    <div>
      <div style={{display:"flex",gap:"8px",marginBottom:"24px"}}>
        {[{id:"order",label:"📋 Order Tests"},{id:"results",label:"📊 My Results"}].map(v=>(
          <button key={v.id} onClick={()=>setView(v.id)} style={{background:view===v.id?T.navy:"transparent",border:`2px solid ${view===v.id?T.navy:T.border}`,borderRadius:"12px",padding:"10px 20px",cursor:"pointer",color:view===v.id?"white":T.textMid,fontSize:"14px",fontFamily:T.font,fontWeight:"600"}}>
            {v.label}
          </button>
        ))}
      </div>

      {view==="order"&&(
        <div style={{display:"grid",gridTemplateColumns:"1fr 300px",gap:"20px"}}>
          <div>
            <div style={{background:T.navyXLight,border:`1.5px solid ${T.navyLight}`,borderRadius:"14px",padding:"16px 20px",marginBottom:"20px"}}>
              <div style={{fontSize:"15px",fontWeight:"700",color:T.navy,marginBottom:"4px"}}>⭐ Recommended For You</div>
              <div style={{fontSize:"13px",color:T.textSoft}}>Based on your conditions, Vytal AI recommends these tests. Your doctor can also order tests directly through Vytal.</div>
              <div style={{marginTop:"10px",display:"flex",gap:"8px",flexWrap:"wrap"}}>
                <span style={{fontSize:"12px",background:"white",border:`1px solid ${T.navyLight}`,borderRadius:"8px",padding:"4px 10px",color:T.navy}}>🤖 AI recommends based on your conditions</span>
                <span style={{fontSize:"12px",background:"white",border:`1px solid ${T.navyLight}`,borderRadius:"8px",padding:"4px 10px",color:T.navy}}>📍 Results auto-sync from Quest & LabCorp</span>
                <span style={{fontSize:"12px",background:"white",border:`1px solid ${T.navyLight}`,borderRadius:"8px",padding:"4px 10px",color:T.navy}}>📧 Results emailed to you in 24-48 hrs</span>
              </div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"12px"}}>
              {LAB_PANELS.map(lab=>(
                <button key={lab.id} onClick={()=>toggle(lab)} style={{background:inCart(lab.id)?lab.light:"white",border:`2px solid ${inCart(lab.id)?lab.color:T.border}`,borderRadius:"16px",padding:"18px",cursor:"pointer",textAlign:"left",transition:"all 0.15s",position:"relative"}}>
                  {lab.recommended&&<div style={{position:"absolute",top:"12px",right:"12px"}}><Pill color={T.navy} bg={T.navyXLight}>Recommended</Pill></div>}
                  <div style={{display:"flex",gap:"12px",alignItems:"center",marginBottom:"12px"}}>
                    <span style={{fontSize:"28px"}}>{lab.icon}</span>
                    <div style={{paddingRight:lab.recommended?"80px":"0"}}>
                      <div style={{fontSize:"14px",fontWeight:"700",color:inCart(lab.id)?lab.color:T.text,lineHeight:"1.3"}}>{lab.name}</div>
                      <Pill color={lab.color} bg={lab.light}>{lab.category}</Pill>
                    </div>
                  </div>
                  <p style={{margin:"0 0 12px",fontSize:"13px",color:T.textSoft,lineHeight:"1.5"}}>{lab.description}</p>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                    <div style={{fontSize:"22px",fontWeight:"800",color:lab.color,fontFamily:T.mono}}>${lab.price}</div>
                    <div style={{fontSize:"12px",color:T.textMuted}}>⏱ {lab.turnaround}{lab.fasting?" · Fast required":""}</div>
                  </div>
                  {inCart(lab.id)&&<div style={{position:"absolute",inset:0,borderRadius:"14px",border:`3px solid ${lab.color}`,pointerEvents:"none",display:"flex",alignItems:"flex-end",justifyContent:"flex-end",padding:"12px"}}><div style={{background:lab.color,color:"white",borderRadius:"50%",width:"28px",height:"28px",display:"flex",alignItems:"center",justifyContent:"center",fontSize:"14px",fontWeight:"700"}}>✓</div></div>}
                </button>
              ))}
            </div>
          </div>

          {/* Cart */}
          <div style={{position:"sticky",top:"20px",alignSelf:"start"}}>
            <Card style={{padding:"20px"}}>
              <div style={{fontSize:"16px",fontWeight:"800",color:T.text,marginBottom:"16px"}}>Your Order</div>
              {cart.length===0?(
                <div style={{textAlign:"center",padding:"28px",background:T.bgSoft,borderRadius:"12px"}}>
                  <div style={{fontSize:"32px",marginBottom:"8px"}}>🧪</div>
                  <div style={{fontSize:"13px",color:T.textMuted}}>Tap a test to add it to your order</div>
                </div>
              ):(
                <>
                  <div style={{display:"flex",flexDirection:"column",gap:"8px",marginBottom:"16px"}}>
                    {cart.map(lab=>(
                      <div key={lab.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 12px",background:T.bgSoft,borderRadius:"10px"}}>
                        <div><div style={{fontSize:"13px",fontWeight:"600",color:T.text}}>{lab.name}</div><div style={{fontSize:"11px",color:T.textMuted}}>{lab.turnaround}</div></div>
                        <div style={{display:"flex",gap:"8px",alignItems:"center"}}>
                          <span style={{fontSize:"14px",fontWeight:"700",color:lab.color,fontFamily:T.mono}}>${lab.price}</span>
                          <button onClick={()=>toggle(lab)} style={{background:"transparent",border:"none",cursor:"pointer",color:T.textMuted,fontSize:"18px",lineHeight:1}}>×</button>
                        </div>
                      </div>
                    ))}
                  </div>
                  <div style={{borderTop:`2px solid ${T.border}`,paddingTop:"12px",marginBottom:"16px"}}>
                    <div style={{display:"flex",justifyContent:"space-between",marginBottom:"6px"}}><span style={{fontSize:"14px",color:T.textSoft}}>Subtotal</span><span style={{fontSize:"14px",color:T.text,fontFamily:T.mono,fontWeight:"700"}}>${total}</span></div>
                    <div style={{display:"flex",justifyContent:"space-between",marginBottom:"6px"}}><span style={{fontSize:"14px",color:T.textSoft}}>Processing fee</span><span style={{fontSize:"14px",color:T.green,fontWeight:"700"}}>Free</span></div>
                    <div style={{display:"flex",justifyContent:"space-between",paddingTop:"8px",borderTop:`1px solid ${T.border}`}}><span style={{fontSize:"16px",fontWeight:"800",color:T.text}}>Total</span><span style={{fontSize:"18px",fontWeight:"800",color:T.navy,fontFamily:T.mono}}>${total}</span></div>
                  </div>
                  <div style={{background:T.bgSoft,borderRadius:"10px",padding:"10px 12px",marginBottom:"14px",fontSize:"12px",color:T.textSoft,lineHeight:"1.6"}}>📍 Visit any Quest Diagnostics or LabCorp near you. Results appear in your dashboard in 24–48 hours.</div>
                  {ordered?(
                    <div style={{background:T.greenLight,border:`2px solid ${T.green}25`,borderRadius:"12px",padding:"16px",textAlign:"center"}}>
                      <div style={{fontSize:"28px",marginBottom:"8px"}}>✅</div>
                      <div style={{fontSize:"15px",fontWeight:"700",color:T.green}}>Order Placed!</div>
                      <div style={{fontSize:"12px",color:T.textSoft,marginTop:"4px"}}>Check your email for the lab slip. Go to any Quest or LabCorp to get your tests done.</div>
                    </div>
                  ):(
                    <BigButton onClick={place} fullWidth>{ordering?"Placing your order…":"Place Order →"}</BigButton>
                  )}
                </>
              )}
              <div style={{marginTop:"12px",fontSize:"11px",color:T.textMuted,textAlign:"center"}}>HSA & FSA cards accepted · Results sync automatically</div>
            </Card>
          </div>
        </div>
      )}

      {view==="results"&&(
        <div>
          {PAST_RESULTS.length===0?(
            <div style={{textAlign:"center",padding:"48px",background:T.bgSoft,borderRadius:"16px",border:`2px dashed ${T.border}`}}>
              <div style={{fontSize:"40px",marginBottom:"14px"}}>🧪</div>
              <h3 style={{margin:"0 0 8px",fontSize:"18px",color:T.text}}>No lab results yet</h3>
              <p style={{color:T.textSoft,fontSize:"14px",margin:"0 0 16px"}}>Order your first lab tests from the Order Tests tab. Results will appear here automatically within 24–48 hours.</p>
              <button onClick={()=>setView("order")} style={{background:T.navy,border:"none",borderRadius:"10px",padding:"11px 24px",cursor:"pointer",color:"white",fontSize:"14px",fontFamily:T.font,fontWeight:"700"}}>Order Lab Tests →</button>
            </div>
          ):(
          <div>
          <div style={{background:T.amberLight,border:`1.5px solid ${T.amber}25`,borderRadius:"12px",padding:"14px 18px",marginBottom:"20px",fontSize:"14px",color:T.textMid}}>
            📋 Your most recent lab results are shown below.
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:"12px"}}>
            {PAST_RESULTS.map((r,i)=>(
              <div key={i} style={{background:"white",borderRadius:"14px",border:`1.5px solid ${T.border}`,padding:"16px 20px",display:"flex",gap:"16px",alignItems:"center",boxShadow:"0 2px 6px rgba(0,0,0,0.04)"}}>
                <div style={{flex:1}}>
                  <div style={{fontSize:"15px",fontWeight:"700",color:T.text}}>{r.test}</div>
                  <div style={{fontSize:"12px",color:T.textMuted,marginTop:"2px"}}>{r.date}</div>
                </div>
                <div style={{textAlign:"right"}}>
                  <div style={{fontSize:"22px",fontWeight:"800",color:r.color,fontFamily:T.mono}}>{r.value}</div>
                  <div style={{fontSize:"12px",color:T.textSoft,marginTop:"2px"}}>{r.what}</div>
                </div>
                <Pill color={r.color} bg={r.status==="normal"?T.greenLight:r.status==="above"?T.amberLight:T.redLight}>{r.status==="normal"?"✓ Normal":r.status==="above"?"↑ Above Target":"↓ Below Target"}</Pill>
              </div>
            ))}
          </div>
          </div>
          )}
        </div>
      )}
    </div>
  );
}

// ─── DIETITIAN BOOKING ────────────────────────────────────────────────────────
function DietitianBooking(){
  const [step,setStep]=useState("browse");
  const [selected,setSelected]=useState(null);
  const [slot,setSlot]=useState(null);
  const [date,setDate]=useState("Jun 28");
  const [booking,setBooking]=useState(false);

  function confirm(){setBooking(true);setTimeout(()=>{setBooking(false);setStep("confirmed");},2200);}

  return(
    <div>
      {step==="browse"&&(
        <div>
          <div style={{background:T.navyXLight,border:`1.5px solid ${T.navyLight}`,borderRadius:"14px",padding:"16px 20px",marginBottom:"24px",display:"flex",gap:"12px",alignItems:"center"}}>
            <div style={{fontSize:"32px"}}>🎯</div>
            <div>
              <div style={{fontSize:"15px",fontWeight:"700",color:T.navy}}>Best match for you: Aisha Williams</div>
              <div style={{fontSize:"13px",color:T.textSoft}}>She specializes in patients managing Diabetes + Hypertension + Heart Disease at the same time — exactly your situation.</div>
            </div>
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:"16px"}}>
            {DIETITIANS.map(d=>(
              <Card key={d.id} style={{padding:"22px"}} accent={d.color}>
                <div style={{display:"flex",gap:"18px",alignItems:"flex-start",flexWrap:"wrap"}}>
                  <div style={{width:"56px",height:"56px",borderRadius:"50%",background:d.light,border:`2px solid ${d.color}30`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"18px",fontWeight:"800",color:d.color,flexShrink:0}}>{d.avatar}</div>
                  <div style={{flex:1,minWidth:"200px"}}>
                    <div style={{display:"flex",gap:"10px",alignItems:"center",flexWrap:"wrap",marginBottom:"4px"}}>
                      <div style={{fontSize:"17px",fontWeight:"800",color:T.text}}>{d.name}</div>
                      <Pill color={d.color} bg={d.light}>{d.badge}</Pill>
                    </div>
                    <div style={{fontSize:"14px",color:T.textSoft,marginBottom:"8px"}}>{d.specialty}</div>
                    <p style={{margin:"0 0 10px",fontSize:"14px",color:T.textMid,lineHeight:"1.6"}}>{d.bio}</p>
                    <div style={{display:"flex",gap:"6px",flexWrap:"wrap",marginBottom:"10px"}}>
                      {d.focus.map((f,i)=><Pill key={i} color={T.textSoft} bg={T.bgMuted}>{f}</Pill>)}
                    </div>
                    <div style={{fontSize:"13px",color:T.textSoft}}>⭐ {d.rating} ({d.reviews} reviews) · Next available: <strong style={{color:T.green}}>{d.nextSlot}</strong></div>
                  </div>
                  <div style={{textAlign:"right",flexShrink:0}}>
                    <div style={{fontSize:"28px",fontWeight:"800",color:d.color,fontFamily:T.mono,marginBottom:"2px"}}>${d.price}</div>
                    <div style={{fontSize:"12px",color:T.textMuted,marginBottom:"14px"}}>per session</div>
                    <BigButton onClick={()=>{setSelected(d);setStep("book");}} color={d.color}>Book Session</BigButton>
                  </div>
                </div>
              </Card>
            ))}
          </div>
        </div>
      )}

      {step==="book"&&selected&&(
        <div style={{maxWidth:"700px"}}>
          <button onClick={()=>setStep("browse")} style={{background:"transparent",border:"none",cursor:"pointer",color:T.textSoft,fontSize:"14px",fontFamily:T.font,marginBottom:"20px",padding:0,display:"flex",alignItems:"center",gap:"6px"}}>← Back to dietitians</button>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"20px"}}>
            <div>
              <Card style={{padding:"20px",marginBottom:"14px"}}>
                <div style={{display:"flex",gap:"14px",alignItems:"center",marginBottom:"14px"}}>
                  <div style={{width:"52px",height:"52px",borderRadius:"50%",background:selected.light,border:`2px solid ${selected.color}30`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"16px",fontWeight:"800",color:selected.color}}>{selected.avatar}</div>
                  <div><div style={{fontSize:"16px",fontWeight:"800",color:T.text}}>{selected.name}</div><div style={{fontSize:"13px",color:T.textSoft,marginTop:"2px"}}>{selected.specialty}</div><div style={{fontSize:"13px",color:T.green,marginTop:"2px"}}>⭐ {selected.rating} · ${selected.price}/session</div></div>
                </div>
                <p style={{margin:0,fontSize:"14px",color:T.textMid,lineHeight:"1.6"}}>{selected.bio}</p>
              </Card>
              <Card style={{padding:"18px"}}>
                <div style={{fontSize:"13px",fontWeight:"700",color:T.textMuted,textTransform:"uppercase",letterSpacing:"1px",marginBottom:"12px"}}>What Happens In Your Session</div>
                {[{emoji:"📹",label:"Video call (HD quality)",sub:"From any device"},{emoji:"⏱",label:"50 minutes",sub:"One-on-one with your dietitian"},{emoji:"📋",label:"Personalized meal plan",sub:"Emailed after your session"},{emoji:"📊",label:"Your health data shared",sub:"Dietitian sees your vitals automatically"}].map((item,i)=>(
                  <div key={i} style={{display:"flex",gap:"12px",padding:"10px 0",borderBottom:i<3?`1px solid ${T.border}`:"",alignItems:"center"}}>
                    <span style={{fontSize:"22px"}}>{item.emoji}</span>
                    <div><div style={{fontSize:"14px",fontWeight:"600",color:T.text}}>{item.label}</div><div style={{fontSize:"12px",color:T.textMuted}}>{item.sub}</div></div>
                  </div>
                ))}
              </Card>
            </div>
            <Card style={{padding:"20px"}}>
              <div style={{fontSize:"16px",fontWeight:"800",color:T.text,marginBottom:"16px"}}>Pick a Date & Time</div>
              <div style={{display:"flex",gap:"8px",marginBottom:"16px",flexWrap:"wrap"}}>
                {["Jun 28","Jun 29","Jun 30","Jul 1","Jul 2"].map(d=>(
                  <button key={d} onClick={()=>setDate(d)} style={{background:date===d?T.navy:"transparent",border:`2px solid ${date===d?T.navy:T.border}`,borderRadius:"10px",padding:"8px 12px",cursor:"pointer",color:date===d?"white":T.textMid,fontSize:"13px",fontFamily:T.font,fontWeight:"600"}}>
                    {d}
                  </button>
                ))}
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:"8px",marginBottom:"20px"}}>
                {TIME_SLOTS.map(s=>(
                  <button key={s} onClick={()=>setSlot(s)} style={{background:slot===s?T.tealLight:"transparent",border:`2px solid ${slot===s?T.teal:T.border}`,borderRadius:"10px",padding:"10px",cursor:"pointer",color:slot===s?T.teal:T.textMid,fontSize:"13px",fontFamily:T.mono,fontWeight:"600"}}>
                    {s}
                  </button>
                ))}
              </div>
              {slot&&(
                <div style={{background:T.greenLight,border:`1.5px solid ${T.green}30`,borderRadius:"12px",padding:"14px",marginBottom:"16px"}}>
                  <div style={{fontSize:"15px",fontWeight:"700",color:T.green}}>📅 {date}, 2026 at {slot}</div>
                  <div style={{fontSize:"13px",color:T.textMid,marginTop:"4px"}}>50-min video session with {selected.name.split(",")[0]}</div>
                </div>
              )}
              <BigButton onClick={confirm} disabled={!slot||booking} fullWidth color={T.teal}>
                {booking?"Booking your session…":slot?"Confirm Booking →":"Select a time to continue"}
              </BigButton>
              <div style={{marginTop:"10px",fontSize:"12px",color:T.textMuted,textAlign:"center"}}>Free cancellation up to 24 hours before · HSA/FSA accepted</div>
            </Card>
          </div>
        </div>
      )}

      {step==="confirmed"&&selected&&(
        <div style={{textAlign:"center",padding:"60px 40px",maxWidth:"480px",margin:"0 auto"}}>
          <div style={{fontSize:"64px",marginBottom:"20px"}}>🎉</div>
          <h2 style={{margin:"0 0 10px",fontSize:"28px",fontWeight:"800",color:T.text,letterSpacing:"-0.4px"}}>You're all booked!</h2>
          <p style={{color:T.textSoft,fontSize:"16px",lineHeight:"1.7",margin:"0 0 28px"}}>Your session with <strong style={{color:T.text}}>{selected.name}</strong> is confirmed for <strong style={{color:T.teal}}>{date}, 2026 at {slot}</strong>. Check your email for details.</p>
          <Card style={{padding:"20px",marginBottom:"24px",textAlign:"left"}}>
            {[{emoji:"📧",label:"Confirmation email sent",sub:"Check your inbox"},{emoji:"📋",label:"Pre-session questionnaire",sub:"Takes 3 minutes — sent to your email"},{emoji:"📊",label:"Your health data",sub:"Shared with your dietitian automatically before the call"}].map((item,i)=>(
              <div key={i} style={{display:"flex",gap:"12px",padding:"10px 0",borderBottom:i<2?`1px solid ${T.border}`:"",alignItems:"center"}}>
                <span style={{fontSize:"22px"}}>{item.emoji}</span>
                <div><div style={{fontSize:"14px",fontWeight:"600",color:T.text}}>{item.label}</div><div style={{fontSize:"12px",color:T.textMuted}}>{item.sub}</div></div>
              </div>
            ))}
          </Card>
          <BigButton onClick={()=>{setStep("browse");setSelected(null);setSlot(null);}} outline>Book Another Session</BigButton>
        </div>
      )}
    </div>
  );
}

// ─── DASHBOARD ────────────────────────────────────────────────────────────────
function Dashboard({patient}){
  const [tasks,setTasks]=useState(CARE_PLAN);
  const done=tasks.filter(t=>t.done).length;
  const alertC={warning:T.amber,info:T.blue,success:T.green,risk:T.red};
  const alerts=ALERTS;

  const [hasDevices]=useState(false); // becomes true once user connects a device
  const vitals=[
    {label:"Blood Sugar",value:"—",unit:"mg/dL",target:"Under 130",status:"none",data:[],color:T.amber,light:T.amberLight,trend:"No data yet",deviceNeeded:"glucometer"},
    {label:"Blood Pressure",value:"—",unit:"mmHg",target:"Under 130/80",status:"none",data:[],color:T.red,light:T.redLight,trend:"No data yet",deviceNeeded:"bp_cuff"},
    {label:"Weight",value:"—",unit:"lbs",target:"Set your target",status:"none",data:[],color:T.blue,light:T.blueLight,trend:"No data yet",deviceNeeded:"scale"},
    {label:"Heart Rate",value:"—",unit:"bpm",target:"60 to 100",status:"none",data:[],color:T.green,light:T.greenLight,trend:"No data yet",deviceNeeded:"watch"},
  ];

  return(
    <div>
      {/* Good morning */}
      <div style={{background:T.navy,borderRadius:"20px",padding:"24px 28px",marginBottom:"24px",display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:"16px"}}>
        <div>
          <div style={{fontSize:"22px",fontWeight:"800",color:"white",marginBottom:"6px"}}>Good morning, {(patient.name||"there").split(" ")[0]} 👋</div>
          <div style={{fontSize:"15px",color:"rgba(255,255,255,0.7)"}}>You've completed <strong style={{color:"white"}}>{done} of {tasks.length}</strong> tasks today. Keep it up!</div>
        </div>
        <div style={{display:"flex",gap:"12px",flexWrap:"wrap"}}>
          <div style={{background:"rgba(255,255,255,0.12)",borderRadius:"12px",padding:"12px 18px",textAlign:"center"}}>
            <div style={{fontSize:"24px",fontWeight:"800",color:"white"}}>{patient.adherenceScore}%</div>
            <div style={{fontSize:"12px",color:"rgba(255,255,255,0.65)"}}>Adherence</div>
          </div>
          <div style={{background:"rgba(255,255,255,0.12)",borderRadius:"12px",padding:"12px 18px",textAlign:"center"}}>
            <div style={{fontSize:"24px",fontWeight:"800",color:"white"}}>{daysSince(patient.joinedAt)}</div>
            <div style={{fontSize:"12px",color:"rgba(255,255,255,0.65)"}}>Days on Plan</div>
          </div>
          <div style={{background:"rgba(255,255,255,0.12)",borderRadius:"12px",padding:"12px 18px",textAlign:"center"}}>
            <div style={{fontSize:"24px",fontWeight:"800",color:"white"}}>0</div>
            <div style={{fontSize:"12px",color:"rgba(255,255,255,0.65)"}}>Devices</div>
          </div>
        </div>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"1.4fr 1fr",gap:"20px"}}>
        <div>
          {/* Vitals */}
          <div style={{fontSize:"18px",fontWeight:"800",color:T.text,marginBottom:"14px"}}>Today's Readings</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"12px",marginBottom:"20px"}}>
            {vitals.map((v,i)=>(
              <Card key={i} accent={v.color} style={{padding:"18px"}}>
                <div style={{fontSize:"12px",fontWeight:"700",color:T.textMuted,textTransform:"uppercase",letterSpacing:"1px",marginBottom:"8px"}}>{v.label}</div>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:"12px"}}>
                  <div style={{fontSize:"30px",fontWeight:"800",color:v.status==="none"?T.textMuted:v.color,fontFamily:T.mono,lineHeight:1}}>{v.value}<div style={{fontSize:"13px",fontWeight:"400",color:T.textMuted,marginTop:"3px"}}>{v.unit}</div></div>
                  {v.status!=="none"&&<Pill color={v.status==="normal"?T.green:T.amber} bg={v.status==="normal"?T.greenLight:T.amberLight}>{v.status==="normal"?"✓ Good":"↑ High"}</Pill>}
                  {v.status==="none"&&<Pill color={T.textMuted} bg={T.bgMuted}>No data</Pill>}
                </div>
                {v.data.length>0?(
                <>
                  <MiniChart data={v.data} color={v.color} height={44}/>
                  <div style={{marginTop:"8px",display:"flex",justifyContent:"space-between"}}>
                    <span style={{fontSize:"11px",color:T.textMuted}}>Target: {v.target}</span>
                    <span style={{fontSize:"11px",color:v.color,fontWeight:"600"}}>{v.trend}</span>
                  </div>
                </>
              ):(
                <div style={{height:"44px",display:"flex",alignItems:"center",justifyContent:"center",background:T.bgSoft,borderRadius:"8px",marginTop:"8px"}}>
                  <span style={{fontSize:"12px",color:T.textMuted}}>Connect a device to see readings</span>
                </div>
              )}
              </Card>
            ))}
          </div>

          {/* Medications */}
          <Card style={{padding:"20px"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"16px"}}>
              <div style={{fontSize:"17px",fontWeight:"800",color:T.text}}>Today's Medications</div>
              <Pill color={T.blue} bg={T.blueLight}>{MEDICATIONS.filter(m=>m.taken).length} of {MEDICATIONS.length} taken</Pill>
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:"8px"}}>
              {MEDICATIONS.map((med,i)=>{
                const cond=CONDITIONS.find(c=>c.id===med.condition);
                return(
                  <div key={i} style={{display:"flex",alignItems:"center",gap:"12px",padding:"12px 14px",background:med.taken?T.bgSoft:T.redLight,borderRadius:"12px",border:`1.5px solid ${med.taken?T.border:T.red+"30"}`}}>
                    <div style={{width:"28px",height:"28px",borderRadius:"50%",background:med.taken?T.green:"white",border:`2px solid ${med.taken?T.green:T.red}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"13px",flexShrink:0,color:"white"}}>{med.taken?"✓":""}</div>
                    <div style={{flex:1}}>
                      <div style={{fontSize:"14px",fontWeight:"600",color:med.taken?T.textMid:T.red}}>{med.name}</div>
                      <div style={{fontSize:"12px",color:T.textMuted}}>{med.time} · {cond?.label}</div>
                    </div>
                    <Pill color={med.taken?T.green:T.red} bg={med.taken?T.greenLight:T.redLight}>{med.taken?"Taken":"Missed"}</Pill>
                  </div>
                );
              })}
            </div>
          </Card>
        </div>

        <div>
          {/* Alerts */}
          <div style={{fontSize:"18px",fontWeight:"800",color:T.text,marginBottom:"14px"}}>Health Alerts</div>
          <div style={{display:"flex",flexDirection:"column",gap:"10px",marginBottom:"20px"}}>
            {ALERTS.map((a,i)=>(
              <div key={i} style={{background:a.light,border:`1.5px solid ${a.color}25`,borderRadius:"14px",padding:"14px 16px",display:"flex",gap:"12px"}}>
                <span style={{fontSize:"20px",flexShrink:0}}>{a.icon}</span>
                <div style={{flex:1}}>
                  <div style={{display:"flex",justifyContent:"space-between",marginBottom:"4px"}}>
                    <div style={{fontSize:"14px",fontWeight:"700",color:T.text}}>{a.title}</div>
                    <div style={{fontSize:"11px",color:T.textMuted}}>{a.time}</div>
                  </div>
                  <div style={{fontSize:"13px",color:T.textMid,lineHeight:"1.5"}}>{a.desc}</div>
                </div>
              </div>
            ))}
          </div>

          {/* Care plan checklist */}
          <Card style={{padding:"20px"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"14px"}}>
              <div style={{fontSize:"17px",fontWeight:"800",color:T.text}}>Today's Tasks</div>
              <div style={{display:"flex",alignItems:"center",gap:"8px"}}>
                <div style={{fontSize:"15px",fontWeight:"800",color:T.teal,fontFamily:T.mono}}>{done}/{tasks.length}</div>
                <div style={{width:"60px",height:"6px",background:T.border,borderRadius:"3px"}}><div style={{width:`${tasks.length?(done/tasks.length)*100:0}%`,height:"100%",background:T.teal,borderRadius:"3px"}}/></div>
              </div>
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:"8px"}}>
              {tasks.map((t,i)=>(
                <div key={i} onClick={()=>setTasks(prev=>prev.map((x,j)=>j===i?{...x,done:!x.done}:x))}
                  style={{display:"flex",gap:"12px",alignItems:"center",padding:"12px 14px",background:t.done?T.bgSoft:"white",borderRadius:"12px",border:`1.5px solid ${t.done?T.border:T.borderMid}`,cursor:"pointer"}}>
                  <span style={{fontSize:"18px",flexShrink:0}}>{t.icon}</span>
                  <div style={{flex:1}}>
                    <div style={{fontSize:"14px",color:t.done?T.textMuted:T.text,textDecoration:t.done?"line-through":"none",fontWeight:"500"}}>{t.task}</div>
                    <div style={{fontSize:"11px",color:T.textMuted,marginTop:"2px"}}>{t.freq}</div>
                  </div>
                  <div style={{width:"22px",height:"22px",borderRadius:"50%",border:`2px solid ${t.done?T.teal:T.border}`,background:t.done?T.teal:"transparent",display:"flex",alignItems:"center",justifyContent:"center",fontSize:"12px",color:"white",flexShrink:0}}>{t.done&&"✓"}</div>
                </div>
              ))}
            </div>
          </Card>
        </div>
      </div>
    </div>
  );
}

// ─── MAIN APP ─────────────────────────────────────────────────────────────────

// ─── NOTIFICATION SETTINGS ────────────────────────────────────────────────────
function NotificationSettings(){
  const [saved,setSaved]=useState(false);
  const [saving,setSaving]=useState(false);
  const [verified,setVerified]=useState({phone:false,email:false});
  const [verifyCode,setVerifyCode]=useState({phone:"",email:""});
  const [showVerify,setShowVerify]=useState({phone:false,email:false});
  const [contact,setContact]=useState({
    phone:"",email:"",
    phoneEnabled:true,emailEnabled:true,
    caretakerPhone:"",caretakerEmail:"",caretakerEnabled:false,
  });
  // Note: In production these would be pre-filled from the user's account
  const [prefs,setPrefs]=useState({
    // Medications
    med_missed:       {on:true,  channels:{sms:true,email:true},  timing:"30min", label:"Missed medication alert",         icon:"💊", desc:"Alert when a medication dose is missed"},
    med_reminder:     {on:true,  channels:{sms:true,email:false}, timing:"1hr",   label:"Medication reminder",             icon:"⏰", desc:"Reminder before medication is due"},
    // Lab tests
    lab_due:          {on:true,  channels:{sms:true,email:true},  timing:"1week", label:"Lab test due soon",               icon:"🧪", desc:"When your next blood test is approaching"},
    lab_results:      {on:true,  channels:{sms:false,email:true}, timing:"now",   label:"Lab results ready",               icon:"📊", desc:"When your results are back from the lab"},
    // Appointments
    appt_reminder:    {on:true,  channels:{sms:true,email:true},  timing:"1day",  label:"Doctor appointment reminder",     icon:"🏥", desc:"Reminder before your scheduled appointment"},
    appt_upcoming:    {on:true,  channels:{sms:false,email:true}, timing:"1week", label:"Upcoming appointment (1 week)",   icon:"📅", desc:"1-week heads up for appointments"},
    // Vitals
    glucose_high:     {on:true,  channels:{sms:true,email:false}, timing:"now",   label:"Blood sugar alert",               icon:"🩸", desc:"When glucose goes above or below safe range"},
    bp_high:          {on:true,  channels:{sms:true,email:false}, timing:"now",   label:"Blood pressure alert",            icon:"❤️",  desc:"When BP is dangerously high"},
    // Risk
    risk_flag:        {on:true,  channels:{sms:false,email:true}, timing:"now",   label:"Health risk flag",                icon:"⚠️", desc:"When AI detects a new health risk"},
    // Care plan
    daily_checkin:    {on:true,  channels:{sms:true,email:false}, timing:"8am",   label:"Daily check-in reminder",         icon:"📋", desc:"Morning reminder to log your health"},
    weekly_summary:   {on:true,  channels:{sms:false,email:true}, timing:"sunday","label":"Weekly health summary",         icon:"📈", desc:"Weekly report sent every Sunday morning"},
  });

  const TIMING_OPTIONS=[
    {id:"now",    label:"Immediately"},
    {id:"15min",  label:"15 minutes before"},
    {id:"30min",  label:"30 minutes before"},
    {id:"1hr",    label:"1 hour before"},
    {id:"2hr",    label:"2 hours before"},
    {id:"3hr",    label:"3 hours before"},
    {id:"6hr",    label:"6 hours before"},
    {id:"12hr",   label:"12 hours before"},
    {id:"1day",   label:"1 day before"},
    {id:"2days",  label:"2 days before"},
    {id:"1week",  label:"1 week before"},
    {id:"8am",    label:"Every day at 8 AM"},
    {id:"sunday", label:"Every Sunday at 9 AM"},
  ];

  function togglePref(key,field){
    setPrefs(p=>({...p,[key]:{...p[key],[field]:!p[key][field]}}));
  }
  function toggleChannel(key,ch){
    setPrefs(p=>({...p,[key]:{...p[key],channels:{...p[key].channels,[ch]:!p[key].channels[ch]}}}));
  }
  function setTiming(key,val){
    setPrefs(p=>({...p,[key]:{...p[key],timing:val}}));
  }

  function sendVerifyCode(type){
    setShowVerify(s=>({...s,[type]:true}));
    // In production this would send a real SMS/email
  }
  function checkCode(type){
    if(verifyCode[type].length===4){ // any 4 digit code works in demo
      setVerified(v=>({...v,[type]:true}));
      setShowVerify(s=>({...s,[type]:false}));
    }
  }

  async function saveSettings(){
    setSaving(true);
    await new Promise(r=>setTimeout(r,1500));
    setSaving(false);setSaved(true);
    setTimeout(()=>setSaved(false),3000);
  }

  const categories=[
    {label:"💊 Medications",      keys:["med_missed","med_reminder"]},
    {label:"🧪 Lab Tests",        keys:["lab_due","lab_results"]},
    {label:"🏥 Appointments",     keys:["appt_reminder","appt_upcoming"]},
    {label:"🩺 Vitals & Alerts",  keys:["glucose_high","bp_high","risk_flag"]},
    {label:"📋 Care Plan",        keys:["daily_checkin","weekly_summary"]},
  ];

  return(
    <div style={{maxWidth:"780px"}}>
      {/* Contact info */}
      <Card style={{padding:"24px",marginBottom:"20px"}}>
        <div style={{fontSize:"17px",fontWeight:"800",color:T.text,marginBottom:"6px"}}>📱 Your Contact Details</div>
        <p style={{fontSize:"14px",color:T.textSoft,margin:"0 0 20px"}}>We send alerts to these contacts. Verify to activate notifications.</p>

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"16px",marginBottom:"20px"}}>
          {/* Phone */}
          <div>
            <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"6px"}}>Your Mobile Number (for SMS)</label>
            <div style={{display:"flex",gap:"8px"}}>
              <input value={contact.phone} onChange={e=>setContact(c=>({...c,phone:e.target.value}))}
                placeholder="+1 (555) 000-0000" type="tel"
                style={{flex:1,padding:"12px 14px",borderRadius:"10px",border:`2px solid ${verified.phone?T.green:T.border}`,fontSize:"15px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none"}}/>
              {contact.phone&&!verified.phone&&(
                <button onClick={()=>sendVerifyCode("phone")} style={{background:T.navy,border:"none",borderRadius:"10px",padding:"0 14px",cursor:"pointer",color:"white",fontSize:"13px",fontFamily:T.font,fontWeight:"700",whiteSpace:"nowrap"}}>Verify</button>
              )}
              {verified.phone&&<div style={{display:"flex",alignItems:"center",gap:"4px",color:T.green,fontSize:"13px",fontWeight:"700",whiteSpace:"nowrap"}}>✅ Verified</div>}
            </div>
            {showVerify.phone&&!verified.phone&&(
              <div style={{marginTop:"8px",background:T.bgSoft,borderRadius:"10px",padding:"12px",border:`1.5px solid ${T.border}`}}>
                <div style={{fontSize:"12px",color:T.textSoft,marginBottom:"8px"}}>Enter any 4-digit code to verify (in production a real SMS is sent)</div>
                <div style={{display:"flex",gap:"8px"}}>
                  <input value={verifyCode.phone} onChange={e=>setVerifyCode(v=>({...v,phone:e.target.value}))}
                    placeholder="1234" maxLength={4}
                    style={{flex:1,padding:"10px",borderRadius:"8px",border:`2px solid ${T.border}`,fontSize:"18px",fontFamily:T.mono,textAlign:"center",outline:"none"}}/>
                  <button onClick={()=>checkCode("phone")} style={{background:T.green,border:"none",borderRadius:"8px",padding:"0 14px",cursor:"pointer",color:"white",fontSize:"13px",fontFamily:T.font,fontWeight:"700"}}>Confirm</button>
                </div>
              </div>
            )}
          </div>

          {/* Email */}
          <div>
            <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"6px"}}>Your Email Address</label>
            <div style={{display:"flex",gap:"8px"}}>
              <input value={contact.email} onChange={e=>setContact(c=>({...c,email:e.target.value}))}
                placeholder="you@email.com" type="email"
                style={{flex:1,padding:"12px 14px",borderRadius:"10px",border:`2px solid ${verified.email?T.green:T.border}`,fontSize:"15px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none"}}/>
              {contact.email&&!verified.email&&(
                <button onClick={()=>sendVerifyCode("email")} style={{background:T.navy,border:"none",borderRadius:"10px",padding:"0 14px",cursor:"pointer",color:"white",fontSize:"13px",fontFamily:T.font,fontWeight:"700",whiteSpace:"nowrap"}}>Verify</button>
              )}
              {verified.email&&<div style={{display:"flex",alignItems:"center",gap:"4px",color:T.green,fontSize:"13px",fontWeight:"700",whiteSpace:"nowrap"}}>✅ Verified</div>}
            </div>
            {showVerify.email&&!verified.email&&(
              <div style={{marginTop:"8px",background:T.bgSoft,borderRadius:"10px",padding:"12px",border:`1.5px solid ${T.border}`}}>
                <div style={{fontSize:"12px",color:T.textSoft,marginBottom:"8px"}}>Enter any 4-digit code to verify (in production a real email is sent)</div>
                <div style={{display:"flex",gap:"8px"}}>
                  <input value={verifyCode.email} onChange={e=>setVerifyCode(v=>({...v,email:e.target.value}))}
                    placeholder="1234" maxLength={4}
                    style={{flex:1,padding:"10px",borderRadius:"8px",border:`2px solid ${T.border}`,fontSize:"18px",fontFamily:T.mono,textAlign:"center",outline:"none"}}/>
                  <button onClick={()=>checkCode("email")} style={{background:T.green,border:"none",borderRadius:"8px",padding:"0 14px",cursor:"pointer",color:"white",fontSize:"13px",fontFamily:T.font,fontWeight:"700"}}>Confirm</button>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Caretaker */}
        <div style={{background:T.navyXLight,border:`1.5px solid ${T.navyLight}`,borderRadius:"12px",padding:"16px 20px"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"10px"}}>
            <div>
              <div style={{fontSize:"14px",fontWeight:"700",color:T.navy}}>👨‍👩‍👧 Also notify a caretaker or family member</div>
              <div style={{fontSize:"12px",color:T.textSoft,marginTop:"2px"}}>They will receive the same alerts you choose below</div>
            </div>
            <button onClick={()=>setContact(c=>({...c,caretakerEnabled:!c.caretakerEnabled}))} style={{
              width:"44px",height:"24px",borderRadius:"12px",border:"none",cursor:"pointer",
              background:contact.caretakerEnabled?T.navy:T.border,position:"relative",transition:"all 0.2s",
            }}>
              <div style={{width:"18px",height:"18px",borderRadius:"50%",background:"white",position:"absolute",top:"3px",left:contact.caretakerEnabled?"23px":"3px",transition:"all 0.2s"}}/>
            </button>
          </div>
          {contact.caretakerEnabled&&(
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"12px",marginTop:"12px"}}>
              <div>
                <label style={{fontSize:"11px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"5px"}}>Caretaker Phone</label>
                <input value={contact.caretakerPhone} onChange={e=>setContact(c=>({...c,caretakerPhone:e.target.value}))}
                  placeholder="+1 (555) 000-0000" type="tel"
                  style={{width:"100%",padding:"10px 14px",borderRadius:"10px",border:`1.5px solid ${T.border}`,fontSize:"14px",fontFamily:T.font,color:T.text,background:"white",outline:"none"}}/>
              </div>
              <div>
                <label style={{fontSize:"11px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"5px"}}>Caretaker Email</label>
                <input value={contact.caretakerEmail} onChange={e=>setContact(c=>({...c,caretakerEmail:e.target.value}))}
                  placeholder="caretaker@email.com" type="email"
                  style={{width:"100%",padding:"10px 14px",borderRadius:"10px",border:`1.5px solid ${T.border}`,fontSize:"14px",fontFamily:T.font,color:T.text,background:"white",outline:"none"}}/>
              </div>
            </div>
          )}
        </div>
      </Card>

      {/* Notification preferences */}
      <Card style={{padding:"24px",marginBottom:"20px"}}>
        <div style={{fontSize:"17px",fontWeight:"800",color:T.text,marginBottom:"4px"}}>🔔 Notification Preferences</div>
        <p style={{fontSize:"14px",color:T.textSoft,margin:"0 0 20px"}}>Choose what alerts you want, how you receive them, and how far in advance.</p>

        {categories.map((cat,ci)=>(
          <div key={ci} style={{marginBottom:"24px"}}>
            <div style={{fontSize:"13px",fontWeight:"800",color:T.navy,textTransform:"uppercase",letterSpacing:"1px",marginBottom:"12px",paddingBottom:"8px",borderBottom:`2px solid ${T.border}`}}>{cat.label}</div>
            {cat.keys.map((key,ki)=>{
              const pref=prefs[key];
              return(
                <div key={key} style={{background:pref.on?T.bgSoft:"white",border:`1.5px solid ${pref.on?T.border:T.border}`,borderRadius:"12px",padding:"14px 16px",marginBottom:"8px"}}>
                  <div style={{display:"flex",gap:"12px",alignItems:"center",marginBottom:pref.on?"12px":"0"}}>
                    <span style={{fontSize:"20px"}}>{pref.icon}</span>
                    <div style={{flex:1}}>
                      <div style={{fontSize:"14px",fontWeight:"700",color:T.text}}>{pref.label}</div>
                      <div style={{fontSize:"12px",color:T.textSoft}}>{pref.desc}</div>
                    </div>
                    {/* Master toggle */}
                    <button onClick={()=>togglePref(key,"on")} style={{
                      width:"44px",height:"24px",borderRadius:"12px",border:"none",cursor:"pointer",flexShrink:0,
                      background:pref.on?T.green:T.border,position:"relative",transition:"all 0.2s",
                    }}>
                      <div style={{width:"18px",height:"18px",borderRadius:"50%",background:"white",position:"absolute",top:"3px",left:pref.on?"23px":"3px",transition:"all 0.2s"}}/>
                    </button>
                  </div>

                  {pref.on&&(
                    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"12px",paddingTop:"12px",borderTop:`1px solid ${T.border}`}}>
                      {/* Channels */}
                      <div>
                        <div style={{fontSize:"11px",fontWeight:"700",color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.5px",marginBottom:"8px"}}>Send Via</div>
                        <div style={{display:"flex",gap:"8px"}}>
                          {[{id:"sms",label:"📱 SMS",color:T.green},{id:"email",label:"📧 Email",color:T.blue}].map(ch=>(
                            <button key={ch.id} onClick={()=>toggleChannel(key,ch.id)} style={{
                              padding:"6px 14px",borderRadius:"20px",cursor:"pointer",fontSize:"12px",fontFamily:T.font,fontWeight:"600",
                              background:pref.channels[ch.id]?ch.color+"15":"transparent",
                              border:`1.5px solid ${pref.channels[ch.id]?ch.color:T.border}`,
                              color:pref.channels[ch.id]?ch.color:T.textMuted,
                            }}>{ch.label}</button>
                          ))}
                        </div>
                      </div>
                      {/* Timing */}
                      <div>
                        <div style={{fontSize:"11px",fontWeight:"700",color:T.textMuted,textTransform:"uppercase",letterSpacing:"0.5px",marginBottom:"8px"}}>When To Notify</div>
                        <select value={pref.timing} onChange={e=>setTiming(key,e.target.value)}
                          style={{width:"100%",padding:"7px 10px",borderRadius:"8px",border:`1.5px solid ${T.border}`,fontSize:"13px",fontFamily:T.font,color:T.text,background:"white",cursor:"pointer",outline:"none"}}>
                          {TIMING_OPTIONS.map(t=><option key={t.id} value={t.id}>{t.label}</option>)}
                        </select>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </Card>

      {/* Quiet hours */}
      <Card style={{padding:"24px",marginBottom:"20px"}}>
        <div style={{fontSize:"17px",fontWeight:"800",color:T.text,marginBottom:"4px"}}>🌙 Quiet Hours</div>
        <p style={{fontSize:"14px",color:T.textSoft,margin:"0 0 16px"}}>No notifications will be sent during these hours (except emergency alerts).</p>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"16px"}}>
          <div>
            <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"6px"}}>Start Time</label>
            <input type="time" defaultValue="22:00"
              style={{width:"100%",padding:"12px 14px",borderRadius:"10px",border:`1.5px solid ${T.border}`,fontSize:"15px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none"}}/>
          </div>
          <div>
            <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"6px"}}>End Time</label>
            <input type="time" defaultValue="07:00"
              style={{width:"100%",padding:"12px 14px",borderRadius:"10px",border:`1.5px solid ${T.border}`,fontSize:"15px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none"}}/>
          </div>
        </div>
        <div style={{marginTop:"12px",display:"flex",gap:"8px",flexWrap:"wrap"}}>
          {["Emergency BP alert","Emergency glucose alert"].map((e,i)=>(
            <div key={i} style={{background:T.redLight,border:`1px solid ${T.red}20`,borderRadius:"8px",padding:"6px 12px",fontSize:"12px",color:T.red,fontWeight:"600"}}>
              ⚡ Always sends: {e}
            </div>
          ))}
        </div>
      </Card>

      {/* Test notification */}
      <Card style={{padding:"20px",marginBottom:"20px",background:T.navyXLight,border:`1.5px solid ${T.navyLight}`}}>
        <div style={{fontSize:"14px",fontWeight:"700",color:T.navy,marginBottom:"8px"}}>🧪 Test Your Notifications</div>
        <p style={{fontSize:"13px",color:T.textSoft,margin:"0 0 14px"}}>Send a test message to make sure everything is working correctly.</p>
        <div style={{display:"flex",gap:"10px",flexWrap:"wrap"}}>
          <button style={{background:T.navy,border:"none",borderRadius:"10px",padding:"10px 20px",cursor:"pointer",color:"white",fontSize:"13px",fontFamily:T.font,fontWeight:"700"}}>📱 Send Test SMS</button>
          <button style={{background:"white",border:`1.5px solid ${T.border}`,borderRadius:"10px",padding:"10px 20px",cursor:"pointer",color:T.navy,fontSize:"13px",fontFamily:T.font,fontWeight:"700"}}>📧 Send Test Email</button>
        </div>
      </Card>

      {/* Save */}
      <div style={{display:"flex",gap:"12px",alignItems:"center"}}>
        <BigButton onClick={saveSettings} color={T.navy}>
          {saving?"Saving…":saved?"✅ Saved!":"Save Notification Settings"}
        </BigButton>
        {saved&&<span style={{fontSize:"14px",color:T.green,fontWeight:"600"}}>Your preferences have been saved!</span>}
      </div>
    </div>
  );
}

// ─── CARETAKER NOTES ──────────────────────────────────────────────────────────
function CaretakerNotes(){
  const today=new Date().toLocaleDateString("en-US",{weekday:"long",month:"long",day:"numeric",year:"numeric"});
  const [note,setNote]=useState("");
  const [mood,setMood]=useState("");
  const [pain,setPain]=useState("");
  const [saving,setSaving]=useState(false);
  const [notes,setNotes]=useState([]); // Empty — notes added by real caretakers
  const [filterAuthor,setFilterAuthor]=useState("all");
  const [expandNote,setExpandNote]=useState(null);

  const MOOD_OPTIONS=[{v:"😊",l:"Good"},{v:"😐",l:"Okay"},{v:"😞",l:"Not Great"},{v:"😴",l:"Tired"},{v:"😤",l:"Uncomfortable"},{v:"🤒",l:"Unwell"}];
  const PAIN_OPTIONS=["None (0)","1/10","2/10","3/10","4/10","5/10","6/10","7/10","8/10","9/10","10/10"];
  const AUTHORS=["all",...[...new Set(notes.map(n=>n.author))]];

  async function saveNote(){
    if(!note.trim()) return;
    setSaving(true);
    await new Promise(r=>setTimeout(r,1000));
    const newNote={
      id:Date.now(),
      date:today,
      time:new Date().toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"}),
      author:"You (Caretaker)",
      mood:mood||"😊",
      pain:pain||"None (0)",
      text:note,
      tags:[],
    };
    setNotes(n=>[newNote,...n]);
    setNote("");setMood("");setPain("");
    setSaving(false);
  }

  const filtered=filterAuthor==="all"?notes:notes.filter(n=>n.author===filterAuthor);

  return(
    <div>
      {/* Add note */}
      <Card style={{padding:"24px",marginBottom:"20px"}}>
        <div style={{fontSize:"17px",fontWeight:"800",color:T.text,marginBottom:"4px"}}>✏️ Add Today's Note</div>
        <p style={{fontSize:"14px",color:T.textSoft,margin:"0 0 18px"}}>{today}</p>

        {/* Mood + Pain */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"16px",marginBottom:"16px"}}>
          <div>
            <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"8px"}}>Patient's Mood Today</label>
            <div style={{display:"flex",gap:"8px",flexWrap:"wrap"}}>
              {MOOD_OPTIONS.map(m=>(
                <button key={m.v} onClick={()=>setMood(m.v)} style={{
                  padding:"6px 12px",borderRadius:"20px",cursor:"pointer",fontSize:"13px",fontFamily:T.font,
                  background:mood===m.v?T.navyXLight:"transparent",
                  border:`1.5px solid ${mood===m.v?T.navy:T.border}`,
                  color:mood===m.v?T.navy:T.textSoft,fontWeight:mood===m.v?"700":"400",
                }}>{m.v} {m.l}</button>
              ))}
            </div>
          </div>
          <div>
            <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"8px"}}>Pain Level</label>
            <select value={pain} onChange={e=>setPain(e.target.value)}
              style={{width:"100%",padding:"10px 14px",borderRadius:"10px",border:`1.5px solid ${T.border}`,fontSize:"14px",fontFamily:T.font,color:T.text,background:"white",outline:"none",cursor:"pointer"}}>
              <option value="">Select pain level</option>
              {PAIN_OPTIONS.map(p=><option key={p} value={p}>{p}</option>)}
            </select>
          </div>
        </div>

        {/* Note text */}
        <textarea value={note} onChange={e=>setNote(e.target.value)}
          placeholder="Write your note here... How was the patient today? Did they take their medications? Any symptoms, changes in behavior, or concerns? Did they eat well? Any appointments or calls?"
          rows={5}
          style={{width:"100%",padding:"14px 16px",borderRadius:"12px",border:`2px solid ${note?T.navy:T.border}`,fontSize:"14px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none",resize:"vertical",lineHeight:"1.6"}}/>

        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:"14px"}}>
          <div style={{fontSize:"12px",color:T.textMuted}}>{note.length} characters · Notes are private and only visible to authorized caretakers</div>
          <BigButton onClick={saveNote} color={T.navy} disabled={!note.trim()||saving}>
            {saving?"Saving…":"💾 Save Note"}
          </BigButton>
        </div>
      </Card>

      {/* Filter + past notes */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"14px",flexWrap:"wrap",gap:"10px"}}>
        <div style={{fontSize:"17px",fontWeight:"800",color:T.text}}>📚 All Past Notes ({notes.length})</div>
        <div style={{display:"flex",gap:"8px",flexWrap:"wrap"}}>
          {AUTHORS.map(a=>(
            <button key={a} onClick={()=>setFilterAuthor(a)} style={{
              padding:"6px 14px",borderRadius:"20px",cursor:"pointer",fontSize:"12px",fontFamily:T.font,fontWeight:"600",
              background:filterAuthor===a?T.navy:"transparent",
              border:`1.5px solid ${filterAuthor===a?T.navy:T.border}`,
              color:filterAuthor===a?"white":T.textSoft,
            }}>{a==="all"?"All Notes":a.split("(")[0].trim()}</button>
          ))}
        </div>
      </div>

      {filtered.length===0&&(
        <div style={{textAlign:"center",padding:"48px",background:T.bgSoft,borderRadius:"16px",border:`2px dashed ${T.border}`}}>
          <div style={{fontSize:"48px",marginBottom:"14px"}}>📝</div>
          <h3 style={{margin:"0 0 8px",fontSize:"18px",color:T.text}}>No notes yet</h3>
          <p style={{color:T.textSoft,fontSize:"14px",margin:0}}>Add your first note above. Family members, nurses, and caregivers can all add daily notes here.</p>
        </div>
      )}
      <div style={{display:"flex",flexDirection:"column",gap:"12px"}}>
        {filtered.map(n=>(
          <Card key={n.id} style={{padding:"20px",cursor:"pointer"}} onClick={()=>setExpandNote(expandNote===n.id?null:n.id)}>
            <div style={{display:"flex",gap:"14px",alignItems:"flex-start"}}>
              <div style={{fontSize:"28px",flexShrink:0}}>{n.mood}</div>
              <div style={{flex:1}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:"6px",flexWrap:"wrap",gap:"8px"}}>
                  <div>
                    <div style={{fontSize:"15px",fontWeight:"700",color:T.text}}>{n.date}</div>
                    <div style={{fontSize:"12px",color:T.textMuted}}>{n.time} · {n.author}</div>
                  </div>
                  <div style={{display:"flex",gap:"8px",alignItems:"center"}}>
                    <Pill color={T.red} bg={T.redLight}>Pain: {n.pain}</Pill>
                    <span style={{color:T.textMuted,fontSize:"16px"}}>{expandNote===n.id?"▲":"▼"}</span>
                  </div>
                </div>
                <p style={{margin:"0 0 10px",fontSize:"14px",color:T.textMid,lineHeight:"1.6",display:expandNote===n.id?"block":"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical",overflow:"hidden"}}>
                  {n.text}
                </p>
                {n.tags.length>0&&(
                  <div style={{display:"flex",gap:"6px",flexWrap:"wrap"}}>
                    {n.tags.map((tag,i)=><Pill key={i} color={T.navy} bg={T.navyXLight}>{tag}</Pill>)}
                  </div>
                )}
              </div>
            </div>
          </Card>
        ))}
      </div>
    </div>
  );
}

// ─── DOCTOR APPOINTMENTS ──────────────────────────────────────────────────────
function DoctorAppointments({patient}){
  const [view,setView]=useState("list"); // list | book | confirmed
  const [bookingStep,setBookingStep]=useState(1);
  const [appt,setAppt]=useState({doctor:"",specialty:"",date:"",time:"",reason:"",location:"",notes:"",notify:"1day"});
  const [appointments,setAppointments]=useState([]); // Empty — user adds their own

  const NOTIFY_OPTIONS=[
    {id:"1hr",label:"1 hour before"},
    {id:"3hr",label:"3 hours before"},
    {id:"6hr",label:"6 hours before"},
    {id:"12hr",label:"12 hours before"},
    {id:"1day",label:"1 day before"},
    {id:"2days",label:"2 days before"},
    {id:"1week",label:"1 week before"},
    {id:"both",label:"1 week + 1 day before"},
  ];

  const SPECIALTIES=[
    "Primary Care / Family Medicine","Endocrinology (Diabetes/Thyroid)","Cardiology (Heart)","Nephrology (Kidney)","Pulmonology (Lungs)","Neurology (Brain/Nerves)","Rheumatology (Arthritis)","Gastroenterology (Digestive)","Psychiatry / Mental Health","Dietitian / Nutritionist","Physical Therapy","Ophthalmology (Eyes)","Dermatology (Skin)","Podiatry (Feet)","Other Specialist",
  ];

  const TIME_SLOTS_APPT=["8:00 AM","8:30 AM","9:00 AM","9:30 AM","10:00 AM","10:30 AM","11:00 AM","11:30 AM","1:00 PM","1:30 PM","2:00 PM","2:30 PM","3:00 PM","3:30 PM","4:00 PM","4:30 PM","5:00 PM"];

  function saveAppt(){
    const newAppt={
      id:Date.now(),
      doctor:appt.doctor||"Your Doctor",
      specialty:appt.specialty||"General",
      date:appt.date,
      time:appt.time,
      location:appt.location||"To be confirmed",
      status:"upcoming",
      reason:appt.reason||"Checkup",
      color:T.blue,light:T.blueLight,icon:"🩺",
      notify:appt.notify,
    };
    setAppointments(prev=>[newAppt,...prev]);
    setView("confirmed");
  }

  const upcoming=appointments.filter(a=>a.status==="upcoming");
  const past=appointments.filter(a=>a.status==="completed");

  if(view==="confirmed") return(
    <div style={{maxWidth:"480px",margin:"0 auto",textAlign:"center",padding:"40px 20px"}}>
      <div style={{fontSize:"64px",marginBottom:"16px"}}>✅</div>
      <h2 style={{margin:"0 0 10px",fontSize:"24px",fontWeight:"800",color:T.text}}>Appointment Saved!</h2>
      <p style={{color:T.textSoft,fontSize:"15px",lineHeight:"1.7",margin:"0 0 24px"}}>
        Your appointment with <strong>{appt.doctor||"your doctor"}</strong> has been added to your Vytal calendar. You'll receive a reminder <strong>{NOTIFY_OPTIONS.find(n=>n.id===appt.notify)?.label}</strong>.
      </p>
      <Card style={{padding:"18px",marginBottom:"20px",textAlign:"left"}}>
        {[{emoji:"📅",l:"Date & Time",v:`${appt.date} at ${appt.time}`},{emoji:"🏥",l:"Location",v:appt.location||"To be confirmed"},{emoji:"🔔",l:"Reminder",v:NOTIFY_OPTIONS.find(n=>n.id===appt.notify)?.label},{emoji:"📱",l:"Notification",v:"SMS + Email will be sent"}].map((item,i)=>(
          <div key={i} style={{display:"flex",gap:"12px",padding:"9px 0",borderBottom:i<3?`1px solid ${T.border}`:"",alignItems:"center"}}>
            <span style={{fontSize:"18px"}}>{item.emoji}</span>
            <div><div style={{fontSize:"13px",fontWeight:"600",color:T.text}}>{item.l}</div><div style={{fontSize:"12px",color:T.textMuted}}>{item.v}</div></div>
          </div>
        ))}
      </Card>
      <BigButton onClick={()=>{setView("list");setAppt({doctor:"",specialty:"",date:"",time:"",reason:"",location:"",notes:"",notify:"1day"});setBookingStep(1);}} color={T.navy}>Back to Appointments</BigButton>
    </div>
  );

  if(view==="book") return(
    <div style={{maxWidth:"620px"}}>
      <button onClick={()=>setView("list")} style={{background:"transparent",border:"none",cursor:"pointer",color:T.textSoft,fontSize:"14px",fontFamily:T.font,marginBottom:"20px",padding:0}}>← Back</button>
      <Card style={{padding:"28px"}}>
        <div style={{fontSize:"18px",fontWeight:"800",color:T.text,marginBottom:"20px"}}>📅 Schedule an Appointment</div>

        {/* Step 1 — Doctor details */}
        <div style={{marginBottom:"20px"}}>
          <div style={{fontSize:"13px",fontWeight:"800",color:T.navy,textTransform:"uppercase",letterSpacing:"1px",marginBottom:"14px",paddingBottom:"8px",borderBottom:`2px solid ${T.border}`}}>Step 1 — Doctor Details</div>
          <div style={{display:"flex",flexDirection:"column",gap:"12px"}}>
            <div>
              <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"6px"}}>Doctor's Name</label>
              <input value={appt.doctor} onChange={e=>setAppt(a=>({...a,doctor:e.target.value}))}
                placeholder="e.g. Dr. Sarah Johnson"
                style={{width:"100%",padding:"12px 14px",borderRadius:"10px",border:`2px solid ${appt.doctor?T.navy:T.border}`,fontSize:"15px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none"}}/>
            </div>
            <div>
              <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"6px"}}>Specialty / Type of Doctor</label>
              <select value={appt.specialty} onChange={e=>setAppt(a=>({...a,specialty:e.target.value}))}
                style={{width:"100%",padding:"12px 14px",borderRadius:"10px",border:`2px solid ${appt.specialty?T.navy:T.border}`,fontSize:"15px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none",cursor:"pointer"}}>
                <option value="">Select specialty</option>
                {SPECIALTIES.map(s=><option key={s} value={s}>{s}</option>)}
              </select>
            </div>
            <div>
              <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"6px"}}>Clinic or Hospital Location</label>
              <input value={appt.location} onChange={e=>setAppt(a=>({...a,location:e.target.value}))}
                placeholder="e.g. Northwestern Medical Center, Chicago"
                style={{width:"100%",padding:"12px 14px",borderRadius:"10px",border:`1.5px solid ${T.border}`,fontSize:"15px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none"}}/>
            </div>
            <div>
              <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"6px"}}>Reason for Visit</label>
              <input value={appt.reason} onChange={e=>setAppt(a=>({...a,reason:e.target.value}))}
                placeholder="e.g. Quarterly diabetes checkup, medication review"
                style={{width:"100%",padding:"12px 14px",borderRadius:"10px",border:`1.5px solid ${T.border}`,fontSize:"15px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none"}}/>
            </div>
          </div>
        </div>

        {/* Step 2 — Date & Time */}
        <div style={{marginBottom:"20px"}}>
          <div style={{fontSize:"13px",fontWeight:"800",color:T.navy,textTransform:"uppercase",letterSpacing:"1px",marginBottom:"14px",paddingBottom:"8px",borderBottom:`2px solid ${T.border}`}}>Step 2 — Date & Time</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"12px",marginBottom:"12px"}}>
            <div>
              <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"6px"}}>Appointment Date</label>
              <input type="date" value={appt.date} onChange={e=>setAppt(a=>({...a,date:e.target.value}))}
                min={new Date().toISOString().split("T")[0]}
                style={{width:"100%",padding:"12px 14px",borderRadius:"10px",border:`2px solid ${appt.date?T.navy:T.border}`,fontSize:"15px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none",cursor:"pointer"}}/>
            </div>
            <div>
              <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"6px"}}>Appointment Time</label>
              <select value={appt.time} onChange={e=>setAppt(a=>({...a,time:e.target.value}))}
                style={{width:"100%",padding:"12px 14px",borderRadius:"10px",border:`2px solid ${appt.time?T.navy:T.border}`,fontSize:"15px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none",cursor:"pointer"}}>
                <option value="">Select time</option>
                {TIME_SLOTS_APPT.map(t=><option key={t} value={t}>{t}</option>)}
              </select>
            </div>
          </div>
        </div>

        {/* Step 3 — Notifications */}
        <div style={{marginBottom:"24px"}}>
          <div style={{fontSize:"13px",fontWeight:"800",color:T.navy,textTransform:"uppercase",letterSpacing:"1px",marginBottom:"14px",paddingBottom:"8px",borderBottom:`2px solid ${T.border}`}}>Step 3 — Set Your Reminder</div>
          <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"8px"}}>Remind Me</label>
          <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:"8px"}}>
            {NOTIFY_OPTIONS.map(n=>(
              <button key={n.id} onClick={()=>setAppt(a=>({...a,notify:n.id}))} style={{
                padding:"10px 8px",borderRadius:"10px",cursor:"pointer",fontSize:"12px",fontFamily:T.font,fontWeight:"600",textAlign:"center",lineHeight:"1.3",
                background:appt.notify===n.id?T.navyXLight:"transparent",
                border:`1.5px solid ${appt.notify===n.id?T.navy:T.border}`,
                color:appt.notify===n.id?T.navy:T.textSoft,
              }}>{n.label}</button>
            ))}
          </div>
          <div style={{marginTop:"10px",background:T.greenLight,border:`1px solid ${T.green}20`,borderRadius:"8px",padding:"10px 14px",fontSize:"13px",color:T.green,fontWeight:"600"}}>
            📱 Reminder will be sent via SMS + Email to your registered contacts
          </div>
        </div>

        {/* Notes */}
        <div style={{marginBottom:"24px"}}>
          <label style={{fontSize:"12px",fontWeight:"700",color:T.textSoft,textTransform:"uppercase",letterSpacing:"0.5px",display:"block",marginBottom:"6px"}}>Notes (optional)</label>
          <textarea value={appt.notes} onChange={e=>setAppt(a=>({...a,notes:e.target.value}))}
            placeholder="Any questions for the doctor? Things to remember to mention?"
            rows={3}
            style={{width:"100%",padding:"12px 14px",borderRadius:"10px",border:`1.5px solid ${T.border}`,fontSize:"14px",fontFamily:T.font,color:T.text,background:T.bg,outline:"none",resize:"vertical"}}/>
        </div>

        <BigButton onClick={saveAppt} color={T.navy} fullWidth
          disabled={!appt.doctor||!appt.date||!appt.time}>
          ✅ Save Appointment
        </BigButton>
      </Card>
    </div>
  );

  return(
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"20px"}}>
        <div style={{fontSize:"15px",color:T.textSoft}}>{upcoming.length} upcoming · {past.length} past</div>
        <BigButton onClick={()=>setView("book")} color={T.navy}>+ Schedule Appointment</BigButton>
      </div>

      {/* Recommended specialists based on conditions + location */}
      <div style={{marginBottom:"28px"}}>
        <div style={{fontSize:"14px",fontWeight:"800",color:T.text,marginBottom:"4px"}}>🩺 Recommended For You</div>
        <div style={{fontSize:"13px",color:T.textSoft,marginBottom:"12px"}}>
          Based on your conditions{patient?.city?<> near <strong>{[patient.city,patient.state,patient.zip].filter(Boolean).join(", ")}{patient.country?`, ${patient.country}`:""}</strong></>:""}
        </div>
        {!patient?.zip&&(
          <div style={{background:T.amberLight,border:`1.5px solid ${T.amber}30`,borderRadius:"10px",padding:"10px 14px",marginBottom:"12px",fontSize:"12px",color:T.amber,fontWeight:"600"}}>
            Add your ZIP/postal code during signup to get closer, more accurate results.
          </div>
        )}
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill, minmax(260px, 1fr))",gap:"12px"}}>
          {getRecommendedSpecialties(patient?.conditions).map(specialty=>(
            <Card key={specialty} style={{padding:"16px"}}>
              <div style={{fontSize:"14px",fontWeight:"700",color:T.text,marginBottom:"10px"}}>{specialty}</div>
              <div style={{display:"flex",gap:"8px",flexWrap:"wrap"}}>
                <a href={mapsSearchUrl(specialty, patient||{})} target="_blank" rel="noopener noreferrer"
                  style={{textDecoration:"none",fontSize:"12px",fontWeight:"700",color:T.navy,background:T.navyXLight,border:`1.5px solid ${T.navyLight}`,borderRadius:"8px",padding:"7px 12px"}}>
                  📍 Find Nearby
                </a>
                <button onClick={()=>{setAppt(a=>({...a,specialty}));setView("book");}}
                  style={{fontSize:"12px",fontWeight:"700",color:T.textMid,background:T.bgSoft,border:`1.5px solid ${T.border}`,borderRadius:"8px",padding:"7px 12px",cursor:"pointer",fontFamily:T.font}}>
                  📅 Schedule
                </button>
              </div>
            </Card>
          ))}
        </div>
      </div>

      {/* Upcoming */}
      {upcoming.length===0&&past.length===0&&(
        <div style={{textAlign:"center",padding:"48px",background:T.bgSoft,borderRadius:"16px",border:`2px dashed ${T.border}`}}>
          <div style={{fontSize:"48px",marginBottom:"14px"}}>🏥</div>
          <h3 style={{margin:"0 0 8px",fontSize:"18px",color:T.text}}>No appointments yet</h3>
          <p style={{color:T.textSoft,fontSize:"14px",margin:"0 0 20px"}}>Add your upcoming doctor visits to get reminders by SMS and email.</p>
          <BigButton onClick={()=>setView("book")} color={T.navy}>+ Schedule Your First Appointment</BigButton>
        </div>
      )}
      {upcoming.length>0&&(
        <div style={{marginBottom:"28px"}}>
          <div style={{fontSize:"14px",fontWeight:"800",color:T.text,marginBottom:"12px"}}>📅 Upcoming Appointments</div>
          <div style={{display:"flex",flexDirection:"column",gap:"12px"}}>
            {upcoming.map(a=>(
              <Card key={a.id} accent={a.color} style={{padding:"20px"}}>
                <div style={{display:"flex",gap:"16px",alignItems:"flex-start",flexWrap:"wrap"}}>
                  <div style={{fontSize:"32px"}}>{a.icon}</div>
                  <div style={{flex:1}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:"8px",marginBottom:"6px"}}>
                      <div>
                        <div style={{fontSize:"16px",fontWeight:"800",color:T.text}}>{a.doctor}</div>
                        <div style={{fontSize:"13px",color:T.textSoft}}>{a.specialty}</div>
                      </div>
                      <Pill color={T.green} bg={T.greenLight}>Upcoming</Pill>
                    </div>
                    <div style={{display:"flex",gap:"16px",flexWrap:"wrap",marginBottom:"8px"}}>
                      <div style={{fontSize:"14px",color:a.color,fontWeight:"700"}}>📅 {a.date} at {a.time}</div>
                      <div style={{fontSize:"13px",color:T.textSoft}}>📍 {a.location}</div>
                    </div>
                    <div style={{fontSize:"13px",color:T.textMid,marginBottom:"8px"}}>📋 {a.reason}</div>
                    <div style={{display:"flex",gap:"8px",flexWrap:"wrap"}}>
                      <Pill color={T.navy} bg={T.navyXLight}>🔔 Reminder: {NOTIFY_OPTIONS.find(n=>n.id===a.notify)?.label}</Pill>
                      <Pill color={T.blue} bg={T.blueLight}>📱 SMS + Email</Pill>
                    </div>
                  </div>
                </div>
              </Card>
            ))}
          </div>
        </div>
      )}

      {/* Past */}
      {past.length>0&&(
        <div>
          <div style={{fontSize:"14px",fontWeight:"800",color:T.text,marginBottom:"12px"}}>✅ Past Appointments</div>
          <div style={{display:"flex",flexDirection:"column",gap:"10px"}}>
            {past.map(a=>(
              <div key={a.id} style={{background:"white",border:`1.5px solid ${T.border}`,borderRadius:"12px",padding:"16px 18px",display:"flex",gap:"14px",alignItems:"center"}}>
                <div style={{fontSize:"24px",opacity:0.6}}>{a.icon}</div>
                <div style={{flex:1}}>
                  <div style={{fontSize:"14px",fontWeight:"700",color:T.textMid}}>{a.doctor} · {a.specialty}</div>
                  <div style={{fontSize:"12px",color:T.textMuted}}>{a.date} at {a.time} · {a.location}</div>
                  <div style={{fontSize:"12px",color:T.textMuted,marginTop:"2px"}}>{a.reason}</div>
                </div>
                <Pill color={T.textSoft} bg={T.bgMuted}>Completed</Pill>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

const NAV = [
  {id:"dashboard",      label:"Dashboard",          icon:"📊"},
  {id:"devices",        label:"My Devices",          icon:"📡"},
  {id:"labs",           label:"Lab Tests",           icon:"🧪"},
  {id:"appointments",   label:"Appointments",        icon:"🏥"},
  {id:"dietitian",      label:"Dietitian",           icon:"🥗"},
  {id:"ai-coach",       label:"AI Health Coach",     icon:"🤖"},
  {id:"risk",           label:"Health Risk Check",   icon:"🧠"},
  {id:"care-plan",      label:"My Care Plan",        icon:"📋"},
  {id:"caretaker-notes",label:"Caretaker Notes",     icon:"📝"},
  {id:"notifications",  label:"Notifications",       icon:"🔔"},
];

export default function App(){
  const [session,setSession]=useState(null);       // {key, account}
  const [checkingSession,setCheckingSession]=useState(true);
  const [patient,setPatient]=useState(null);
  const [tab,setTab]=useState("dashboard");

  // Restore a session (if any) on load — does not expose the password, only the account record
  useEffect(()=>{
    try{
      const key=localStorage.getItem(SESSION_KEY);
      if(key){
        const accounts=loadAccounts();
        const acct=accounts[key];
        if(acct){
          setSession({key, account:acct});
          if(acct.profile) setPatient(acct.profile);
        }
      }
    }catch{}
    setCheckingSession(false);
  },[]);

  function handleAuthenticated({key, account}){
    setSession({key, account});
    setPatient(account.profile || null);
  }

  function handleOnboardingComplete(p){
    const fullName=p.fullName||p.name||"Friend";
    const profile={
      name:fullName,
      age:p.age||parseInt(p.age)||0,
      dob:p.dob||"",
      email:p.email||"",
      phone:p.phone||"",
      city:p.city||"",
      state:p.state||"",
      country:p.country||"",
      zip:p.zip||"",
      conditions:p.conditions||[],
      avatar:fullName.split(" ").filter(Boolean).map(n=>n[0]).join("").toUpperCase().slice(0,2)||"U",
      nextAppt:null,          // real value once an appointment is booked
      adherenceScore:0,       // real value once care-plan tasks are tracked
      joinedAt:new Date().toISOString(),
    };
    setPatient(profile);
    if(session){
      const accounts=loadAccounts();
      accounts[session.key]={...accounts[session.key], profile};
      saveAccounts(accounts);
      setSession(s=>({...s, account:accounts[session.key]}));
    }
  }

  function handleLogout(){
    try{ localStorage.removeItem(SESSION_KEY); }catch{}
    setSession(null);
    setPatient(null);
    setTab("dashboard");
  }

  if(checkingSession) return null;
  if(!session) return <Auth onAuthenticated={handleAuthenticated}/>;
  if(!patient) return <Onboarding onComplete={handleOnboardingComplete}/>;

  return(
    <div style={{minHeight:"100vh",background:T.bgSoft,color:T.text,fontFamily:T.font}}>
      <style>{`
        @keyframes spin{to{transform:rotate(360deg)}}
        @keyframes pulse{0%,100%{opacity:.4}50%{opacity:1}}
        @keyframes bounce{0%,100%{transform:translateY(0)}50%{transform:translateY(-5px)}}
        *{box-sizing:border-box}
        ::-webkit-scrollbar{width:6px}
        ::-webkit-scrollbar-track{background:transparent}
        ::-webkit-scrollbar-thumb{background:#CBD5E1;border-radius:3px}
        input:focus{outline:none}
        button:focus-visible{outline:3px solid #1B2B4B;outline-offset:2px}
      `}</style>

      {/* Sidebar */}
      <div style={{position:"fixed",left:0,top:0,bottom:0,width:"240px",background:"white",borderRight:`1.5px solid ${T.border}`,display:"flex",flexDirection:"column",zIndex:10,overflowY:"auto",boxShadow:"2px 0 12px rgba(0,0,0,0.04)"}}>
        {/* Logo */}
        <div style={{padding:"24px 20px 18px",borderBottom:`1.5px solid ${T.border}`}}>
          <div style={{display:"inline-flex",alignItems:"center",gap:"10px",background:T.navy,borderRadius:"14px",padding:"10px 16px"}}>
            <span style={{fontSize:"18px"}}>⚕️</span>
            <span style={{fontSize:"18px",fontWeight:"800",color:"white",letterSpacing:"-0.3px"}}>Vytal</span>
          </div>
        </div>

        {/* Patient */}
        <div style={{padding:"16px 20px",borderBottom:`1.5px solid ${T.border}`}}>
          <div style={{display:"flex",gap:"12px",alignItems:"center",marginBottom:"12px"}}>
            <div style={{width:"44px",height:"44px",borderRadius:"50%",background:T.navyXLight,border:`2px solid ${T.navyLight}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"14px",fontWeight:"800",color:T.navy,flexShrink:0}}>
              {(patient.name||"U").split(" ").map(n=>n[0]).join("").toUpperCase().slice(0,2)}
            </div>
            <div>
              <div style={{fontSize:"15px",fontWeight:"800",color:T.text}}>{patient.name}</div>
              <div style={{fontSize:"12px",color:T.textSoft}}>Age {patient.age}</div>
            </div>
          </div>
          <div style={{marginBottom:"10px"}}>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:"5px"}}>
              <span style={{fontSize:"12px",fontWeight:"600",color:T.textSoft}}>Daily adherence</span>
              <span style={{fontSize:"12px",fontWeight:"800",color:T.teal}}>{patient.adherenceScore}%</span>
            </div>
            <div style={{height:"6px",background:T.bgMuted,borderRadius:"3px"}}><div style={{width:`${patient.adherenceScore}%`,height:"100%",background:T.teal,borderRadius:"3px"}}/></div>
          </div>
          <div style={{display:"flex",gap:"5px",flexWrap:"wrap"}}>
            {patient.conditions.slice(0,3).map(cid=>{const c=CONDITIONS.find(x=>x.id===cid);return c?<Pill key={cid} color={c.color} bg={c.light}>{c.emoji}</Pill>:null;})}
            <Pill color={patient.conditions?.length>0?T.blue:T.textSoft} bg={patient.conditions?.length>0?T.blueLight:T.bgMuted}>{patient.conditions?.length||0} condition{patient.conditions?.length!==1?"s":""}</Pill>
          </div>
        </div>

        {/* Nav */}
        <nav style={{flex:1,padding:"12px"}}>
          {NAV.map(n=>(
            <button key={n.id} onClick={()=>setTab(n.id)} style={{
              display:"flex",alignItems:"center",gap:"12px",width:"100%",
              padding:"12px 14px",
              background:tab===n.id?T.navyXLight:"transparent",
              border:tab===n.id?`1.5px solid ${T.navyLight}`:"1.5px solid transparent",
              borderRadius:"12px",cursor:"pointer",textAlign:"left",
              marginBottom:"3px",
              color:tab===n.id?T.navy:T.textSoft,
              fontSize:"14px",fontFamily:T.font,fontWeight:tab===n.id?"700":"500",
              transition:"all 0.15s",
            }}>
              <span style={{fontSize:"17px"}}>{n.icon}</span>
              {n.label}
              {n.id==="ai-coach"&&<span style={{marginLeft:"auto",width:"8px",height:"8px",borderRadius:"50%",background:T.green}}/>}
            </button>
          ))}
        </nav>

        <div style={{padding:"16px 20px",borderTop:`1.5px solid ${T.border}`,background:T.bgSoft}}>
          <div style={{fontSize:"12px",color:T.textMuted,lineHeight:"1.7",marginBottom:"12px"}}>
            Next appointment<br/>
            <strong style={{color:T.text,fontSize:"13px"}}>{patient.nextAppt||"Not scheduled"}</strong>
          </div>
          <button onClick={handleLogout} style={{width:"100%",padding:"9px",borderRadius:"10px",border:`1.5px solid ${T.border}`,background:"white",cursor:"pointer",color:T.textSoft,fontSize:"12px",fontFamily:T.font,fontWeight:"700"}}>
            🚪 Log Out
          </button>
        </div>
      </div>

      {/* Main content */}
      <div style={{marginLeft:"240px",minHeight:"100vh"}}>
        {/* Top bar */}
        <div style={{background:"white",borderBottom:`1.5px solid ${T.border}`,padding:"16px 32px",display:"flex",alignItems:"center",gap:"16px",position:"sticky",top:0,zIndex:9,boxShadow:"0 2px 8px rgba(0,0,0,0.04)"}}>
          <div>
            <h1 style={{margin:0,fontSize:"20px",fontWeight:"800",color:T.text,letterSpacing:"-0.3px"}}>
              {NAV.find(n=>n.id===tab)?.icon} {NAV.find(n=>n.id===tab)?.label}
            </h1>
          </div>
          <div style={{marginLeft:"auto",display:"flex",gap:"10px",alignItems:"center",flexWrap:"wrap"}}>
            <Pill color={T.textSoft} bg={T.bgMuted}>📡 No devices yet</Pill>
            <Pill color={T.textSoft} bg={T.bgMuted}>🧠 No risk check yet</Pill>
            <Pill color={T.navy} bg={T.navyXLight}>Next visit: {patient.nextAppt||"Not scheduled"}</Pill>
          </div>
        </div>

        {/* Page */}
        <div style={{padding:"28px 32px"}}>
          {tab==="dashboard"        && <Dashboard patient={patient}/>}
          {tab==="devices"          && <><SectionHead sub="Live readings from all your health devices. Data updates automatically.">My Connected Devices</SectionHead><ConnectedDevices/></>}
          {tab==="labs"             && <><SectionHead sub="Order blood tests and view your results — all in plain English.">Lab Tests</SectionHead><LabOrders/></>}
          {tab==="appointments"     && <><SectionHead sub="Track doctor visits, set reminders, and never miss an appointment.">Doctor Appointments</SectionHead><DoctorAppointments patient={patient}/></>}
          {tab==="dietitian"        && <><SectionHead sub="Book a video session with a dietitian who specializes in your conditions.">Dietitian Consultations</SectionHead><DietitianBooking/></>}
          {tab==="ai-coach"         && <div style={{maxWidth:"800px"}}><SectionHead sub="Ask anything about your health — your AI coach knows your full health history.">AI Health Coach</SectionHead><Card style={{overflow:"hidden"}}><div style={{height:"620px",display:"flex",flexDirection:"column"}}><AICoach patient={patient}/></div></Card></div>}
          {tab==="risk"             && <Card><RiskAnalyzer patient={patient}/></Card>}
          {tab==="care-plan"        && <Card><CarePlanAI patient={patient}/></Card>}
          {tab==="caretaker-notes"  && <><SectionHead sub="Daily notes from family members, nurses, and caregivers — all in one place.">Caretaker Notes</SectionHead><CaretakerNotes/></>}
          {tab==="notifications"    && <><SectionHead sub="Register your phone and email, and choose exactly which alerts you receive.">Notification Settings</SectionHead><NotificationSettings/></>}
        </div>
      </div>
    </div>
  );
}
